12	// beadStore returns a bead.Store rooted at the per-request working directory
13	// (from ctx via WithWorkingDir, falling back to r.WorkingDir).
14	func (r *mutationResolver) beadStore(ctx context.Context) *bead.Store {
15		return bead.NewStore(filepath.Join(r.workingDir(ctx), ".ddx"))
16	}
