18	// beadModelFromBead converts a bead.Bead to the GraphQL Bead model.
19	func beadModelFromBead(b *bead.Bead) *Bead {
20		gql := &Bead{
21			ID:        b.ID,
22			Title:     b.Title,
23			Status:    b.Status,
24			Priority:  b.Priority,
25			IssueType: b.IssueType,
26			CreatedAt: b.CreatedAt.UTC().Format(time.RFC3339),
27			UpdatedAt: b.UpdatedAt.UTC().Format(time.RFC3339),
28			Labels:    b.Labels,
29		}
30		if b.Owner != "" {
31			gql.Owner = &b.Owner
32		}
33		if b.CreatedBy != "" {
34			gql.CreatedBy = &b.CreatedBy
35		}
36		if b.Parent != "" {
37			gql.Parent = &b.Parent
38		}
39		if b.Description != "" {
40			gql.Description = &b.Description
41		}
42		if b.Acceptance != "" {
43			gql.Acceptance = &b.Acceptance
44		}
45		if b.Notes != "" {
46			gql.Notes = &b.Notes
47		}
48		for _, d := range b.Dependencies {
49			dep := &Dependency{
50				IssueID:     d.IssueID,
51				DependsOnID: d.DependsOnID,
52				Type:        d.Type,
53			}
54			if d.CreatedAt != "" {
55				dep.CreatedAt = &d.CreatedAt
56			}
57			if d.CreatedBy != "" {
58				dep.CreatedBy = &d.CreatedBy
59			}
60			if d.Metadata != "" {
61				dep.Metadata = &d.Metadata
62			}
63			gql.Dependencies = append(gql.Dependencies, dep)
64		}
65		return gql
66	}
