68	// BeadCreate is the resolver for the beadCreate mutation.
69	func (r *mutationResolver) BeadCreate(ctx context.Context, input BeadInput) (*Bead, error) {
70		if r.workingDir(ctx) == "" {
71			return nil, fmt.Errorf("working directory not configured")
72		}
73		if input.Title == "" {
74			return nil, fmt.Errorf("title is required")
75		}
76	
77		b := &bead.Bead{
78			Title: input.Title,
79		}
80		if input.Status != nil {
81			b.Status = *input.Status
82		}
83		if input.Priority != nil {
84			b.Priority = *input.Priority
85		}
86		if input.IssueType != nil {
87			b.IssueType = *input.IssueType
88		}
89		if input.Labels != nil {
90			b.Labels = input.Labels
91		}
92		if input.Parent != nil {
93			b.Parent = *input.Parent
94		}
95		if input.Description != nil {
96			b.Description = *input.Description
97		}
98		if input.Acceptance != nil {
99			b.Acceptance = *input.Acceptance
100		}
101		if input.Notes != nil {
102			b.Notes = *input.Notes
103		}
104	
105		store := r.beadStore(ctx)
106		if err := store.Create(b); err != nil {
107			return nil, err
108		}
109		return beadModelFromBead(b), nil
110	}
