112	// BeadUpdate is the resolver for the beadUpdate mutation.
113	func (r *mutationResolver) BeadUpdate(ctx context.Context, id string, input BeadUpdateInput) (*Bead, error) {
114		if r.workingDir(ctx) == "" {
115			return nil, fmt.Errorf("working directory not configured")
116		}
117	
118		store := r.beadStore(ctx)
119		err := store.Update(id, func(b *bead.Bead) {
120			if input.Title != nil {
121				b.Title = *input.Title
122			}
123			if input.Status != nil {
124				b.Status = *input.Status
125			}
126			if input.Priority != nil {
127				b.Priority = *input.Priority
128			}
129			if input.IssueType != nil {
130				b.IssueType = *input.IssueType
131			}
132			if input.Labels != nil {
133				b.Labels = input.Labels
134			}
135			if input.Parent != nil {
136				b.Parent = *input.Parent
137			}
138			if input.Description != nil {
139				b.Description = *input.Description
140			}
141			if input.Acceptance != nil {
142				b.Acceptance = *input.Acceptance
143			}
144			if input.Notes != nil {
145				b.Notes = *input.Notes
146			}
147		})
148		if err != nil {
149			return nil, err
150		}
151	
152		b, err := store.Get(id)
153		if err != nil {
154			return nil, err
155		}
156		return beadModelFromBead(b), nil
157	}
