1	package bead
2	
3	import (
4		"strings"
5		"time"
6	)
7	
8	const (
9		ExtraRetryAfter      = "execute-loop-retry-after"
10		ExtraLastStatus      = "execute-loop-last-status"
11		ExtraLastDetail      = "execute-loop-last-detail"
12		ExtraNoChangesCount  = "execute-loop-no-changes-count"
13		ExtraExecutionElig   = "execution-eligible"
14		ExtraExecutionReason = "execution-skip-reason"
15	
16		LabelNoChangesUnverified      = "triage:no-changes-unverified"
17		LabelNoChangesUnjustified     = "triage:no-changes-unjustified"
18		LabelNeedsInvestigation       = "triage:needs-investigation"
19		LabelNeedsHuman               = "needs_human"
20		LabelReconciledNoChangesState = "reconciled:no-changes-state"
21	)
22	
23	var noChangesManagementKeys = []string{
24		ExtraRetryAfter,
25		ExtraLastStatus,
26		ExtraLastDetail,
27		ExtraNoChangesCount,
28	}
29	
30	var noChangesTriageLabels = []string{
31		LabelNoChangesUnverified,
32		LabelNoChangesUnjustified,
33	}
34	
35	// ReconcileOptions controls stale no_changes lifecycle reconciliation.
36	type ReconcileOptions struct {
37		Apply bool
38		Now   time.Time
39		IDs   []string
40	}
41	
42	// ReconcilePlan is a single proposed or applied lifecycle repair.
43	type ReconcilePlan struct {
44		BeadID         string         `json:"bead_id"`
45		Reason         string         `json:"reason"`
46		CurrentFields  map[string]any `json:"current_fields,omitempty"`
47		SetFields      map[string]any `json:"set_fields,omitempty"`
48		ClearFields    []string       `json:"clear_fields,omitempty"`
49		RemoveLabels   []string       `json:"remove_labels,omitempty"`
50		AddLabels      []string       `json:"add_labels,omitempty"`
51		CloseSatisfied bool           `json:"close_satisfied,omitempty"`
52		Applied        bool           `json:"applied"`
53	}
54	
55	// ReconcileLifecycleMetadata returns conservative repairs for stale
56	// no_changes management fields. With Apply=false it is a dry run; with
57	// Apply=true it mutates through the Store API and appends reconciliation
58	// evidence.
59	func (s *Store) ReconcileLifecycleMetadata(opts ReconcileOptions) ([]ReconcilePlan, error) {
60		if opts.Now.IsZero() {
61			opts.Now = time.Now().UTC()
62		}
63		beads, err := s.ReadAll()
64		if err != nil {
65			return nil, err
66		}
67		childrenByParent := make(map[string]int)
68		idFilter := make(map[string]bool, len(opts.IDs))
69		for _, id := range opts.IDs {
70			if strings.TrimSpace(id) != "" {
71				idFilter[strings.TrimSpace(id)] = true
72			}
73		}
74		for _, b := range beads {
75			if b.Parent != "" {
76				childrenByParent[b.Parent]++
77			}
78		}
79	
80		var plans []ReconcilePlan
81		for _, b := range beads {
82			if len(idFilter) > 0 && !idFilter[b.ID] {
83				continue
84			}
85			events, _ := s.eventsForBead(&b)
86			if p, ok := planLifecycleReconcile(b, events, childrenByParent[b.ID], opts.Now); ok {
87				if opts.Apply {
88					if err := s.applyReconcilePlan(p); err != nil {
89						return plans, err
90					}
91					p.Applied = true
92				}
93				plans = append(plans, p)
94			}
95		}
96		return plans, nil
97	}
98	
99	func planLifecycleReconcile(b Bead, events []BeadEvent, childCount int, now time.Time) (ReconcilePlan, bool) {
100		p := ReconcilePlan{
101			BeadID:        b.ID,
102			CurrentFields: currentLifecycleFields(b),
103		}
104		latest := latestLifecycleEvent(events)
105	
106		if b.Status == StatusClosed && hasClosedNoChangesResidue(b) {
107			p.Reason = "closed bead has stale no_changes lifecycle metadata"
108			p.ClearFields = noChangesFieldsPresent(b)
109			p.RemoveLabels = noChangesLabelsPresent(b)
110			return p, len(p.ClearFields) > 0 || len(p.RemoveLabels) > 0
111		}
112	
113		if isSuccessEvent(latest) && hasNoChangesResidue(b) {
114			p.Reason = "latest terminal success supersedes stale no_changes lifecycle metadata"
115			p.ClearFields = noChangesFieldsPresent(b)
116			p.RemoveLabels = noChangesLabelsPresent(b)
117			return p, len(p.ClearFields) > 0 || len(p.RemoveLabels) > 0
118		}
119	
120		if latest.Kind == "no_changes_verified" && b.Status != StatusClosed {
121			p.Reason = "verified no_changes evidence closes as already_satisfied"
122			p.ClearFields = noChangesFieldsPresent(b)
123			p.RemoveLabels = noChangesLabelsPresent(b)
124			p.CloseSatisfied = true
125			return p, true
126		}
127	
128		if isNoViableProviderEvent(latest) && hasLabel(b, LabelNeedsInvestigation) {
129			p.Reason = "no_viable_provider is retryable transport state; clear stale needs-investigation label"
130			p.RemoveLabels = []string{LabelNeedsInvestigation}
131			return p, true
132		}
133	
134		if hasLabel(b, LabelNeedsInvestigation) || latest.Kind == "no_changes_needs_investigation" {
135			if hasRetryAfter(b) || hasAnyExtra(b, ExtraLastStatus, ExtraLastDetail) {
136				p.Reason = "needs_investigation is non-retryable; clear cooldown metadata"
137				p.ClearFields = noChangesFieldsPresent(b)
138				if !hasLabel(b, LabelNeedsInvestigation) {
139					p.AddLabels = append(p.AddLabels, LabelNeedsInvestigation)
140				}
141				return p, len(p.ClearFields) > 0 || len(p.AddLabels) > 0
142			}
143		}
144	
145		if isExpiredRetryAfter(b, now) {
146			p.Reason = "expired retry-after metadata no longer blocks execution"
147			p.ClearFields = []string{ExtraRetryAfter}
148			return p, true
149		}
150	
151		if isContainerBead(b, childCount) && noChangesCount(b) > 0 {
152			if b.Extra != nil {
153				if eligible, ok := b.Extra[ExtraExecutionElig].(bool); ok && !eligible {
154					return ReconcilePlan{}, false
155				}
156			}
157			p.Reason = "parent/epic work is owned by child beads"
158			p.SetFields = map[string]any{
159				ExtraExecutionElig:   false,
160				ExtraExecutionReason: "parent/epic container; execute child beads first",
161			}
162			return p, true
163		}
164	
165		return ReconcilePlan{}, false
166	}
167	
168	func (s *Store) applyReconcilePlan(p ReconcilePlan) error {
169		err := s.Update(p.BeadID, func(b *Bead) {
170			if b.Extra == nil {
171				b.Extra = make(map[string]any)
172			}
173			for _, key := range p.ClearFields {
174				delete(b.Extra, key)
175			}
176			for key, value := range p.SetFields {
177				b.Extra[key] = value
178			}
179			for _, label := range p.RemoveLabels {
180				removeLabel(b, label)
181			}
182			for _, label := range p.AddLabels {
183				addLabel(b, label)
184			}
185			addLabel(b, LabelReconciledNoChangesState)
186			if p.CloseSatisfied {
187				b.Status = StatusClosed
188			}
189			appendInlineEvent(b, BeadEvent{
190				Kind:      "lifecycle_reconciled",
191				Summary:   p.Reason,
192				Actor:     "ddx",
193				Source:    "ddx bead reconcile",
194				CreatedAt: time.Now().UTC(),
195			})
196		})
197		if err != nil {
198			return err
199		}
200		if p.CloseSatisfied {
201			return s.externalizeEvents(p.BeadID)
202		}
203		return nil
204	}
205	
206	func appendInlineEvent(b *Bead, event BeadEvent) {
207		if event.CreatedAt.IsZero() {
208			event.CreatedAt = time.Now().UTC()
209		}
210		events := decodeBeadEvents(b.Extra["events"])
211		events = append(events, event)
212		b.Extra["events"] = encodeEventsForExtra(events)
213	}
214	
215	func currentLifecycleFields(b Bead) map[string]any {
216		out := make(map[string]any)
217		for _, key := range noChangesManagementKeys {
218			if b.Extra != nil {
219				if v, ok := b.Extra[key]; ok {
220					out[key] = v
221				}
222			}
223		}
224		for _, label := range append(noChangesTriageLabels, LabelNeedsInvestigation) {
225			if hasLabel(b, label) {
226				out["label:"+label] = true
227			}
228		}
229		return out
230	}
231	
232	func latestLifecycleEvent(events []BeadEvent) BeadEvent {
233		var latest BeadEvent
234		for _, e := range events {
235			if strings.HasPrefix(e.Kind, "no_changes_") || e.Kind == "execute-bead" {
236				latest = e
237			}
238		}
239		return latest
240	}
241	
242	func isSuccessEvent(e BeadEvent) bool {
243		if e.Kind != "execute-bead" {
244			return false
245		}
246		summary := strings.TrimSpace(e.Summary)
247		return summary == "success" || summary == "already_satisfied"
248	}
249	
250	func isNoViableProviderEvent(e BeadEvent) bool {
251		if e.Kind != "execute-bead" || strings.TrimSpace(e.Summary) != "execution_failed" {
252			return false
253		}
254		body := strings.ToLower(e.Body)
255		return strings.Contains(body, "no viable provider") ||
256			strings.Contains(body, "all tiers exhausted")
257	}
258	
259	func hasNoChangesResidue(b Bead) bool {
260		return len(noChangesFieldsPresent(b)) > 0 || len(noChangesLabelsPresent(b)) > 0
261	}
262	
263	func hasClosedNoChangesResidue(b Bead) bool {
264		return len(noChangesLabelsPresent(b)) > 0 || hasAnyExtra(b, ExtraRetryAfter, ExtraLastStatus, ExtraLastDetail)
265	}
266	
267	func noChangesFieldsPresent(b Bead) []string {
268		var keys []string
269		for _, key := range noChangesManagementKeys {
270			if b.Extra != nil {
271				if _, ok := b.Extra[key]; ok {
272					keys = append(keys, key)
273				}
274			}
275		}
276		return keys
277	}
278	
279	func noChangesLabelsPresent(b Bead) []string {
280		var labels []string
281		for _, label := range noChangesTriageLabels {
282			if hasLabel(b, label) {
283				labels = append(labels, label)
284			}
285		}
286		return labels
287	}
288	
289	func hasRetryAfter(b Bead) bool {
290		return hasAnyExtra(b, ExtraRetryAfter)
291	}
292	
293	func hasAnyExtra(b Bead, keys ...string) bool {
294		for _, key := range keys {
295			if b.Extra != nil {
296				if _, ok := b.Extra[key]; ok {
297					return true
298				}
299			}
300		}
301		return false
302	}
303	
304	func isExpiredRetryAfter(b Bead, now time.Time) bool {
305		raw, ok := b.Extra[ExtraRetryAfter].(string)
306		if !ok || raw == "" {
307			return false
308		}
309		t, err := time.Parse(time.RFC3339, raw)
310		return err == nil && !t.After(now)
311	}
312	
313	func noChangesCount(b Bead) int {
314		if b.Extra == nil {
315			return 0
316		}
317		switch v := b.Extra[ExtraNoChangesCount].(type) {
318		case int:
319			return v
320		case int64:
321			return int(v)
322		case float64:
323			return int(v)
324		}
325		return 0
326	}
327	
328	func isContainerBead(b Bead, childCount int) bool {
329		if childCount == 0 {
330			return false
331		}
332		return b.IssueType == "epic" || strings.HasPrefix(strings.ToLower(b.Title), "epic:")
333	}
334	
335	func hasLabel(b Bead, label string) bool {
336		for _, existing := range b.Labels {
337			if existing == label {
338				return true
339			}
340		}
341		return false
342	}
343	
344	func addLabel(b *Bead, label string) {
345		for _, existing := range b.Labels {
346			if existing == label {
347				return
348			}
349		}
350		b.Labels = append(b.Labels, label)
351	}
352	
353	func removeLabel(b *Bead, label string) {
354		out := b.Labels[:0]
355		for _, existing := range b.Labels {
356			if existing != label {
357				out = append(out, existing)
358			}
359		}
360		b.Labels = out
361	}
