397	// WriteAll writes all beads to the configured backend, sorted by ID.
398	func (s *Store) WriteAll(beads []Bead) error {
399		sort.Slice(beads, func(i, j int) bool {
400			return beads[i].ID < beads[j].ID
401		})
402	
403		if s.backend != nil {
404			return s.backend.WriteAll(beads)
405		}
406	
407		if err := os.MkdirAll(s.Dir, 0o755); err != nil {
408			return fmt.Errorf("bead: mkdir: %w", err)
409		}
410	
411		tmp, err := tmpPath(s.File)
412		if err != nil {
413			return fmt.Errorf("bead: tmp name: %w", err)
414		}
415		f, err := os.OpenFile(tmp, os.O_WRONLY|os.O_CREATE|os.O_EXCL, 0o644)
416		if err != nil {
417			return fmt.Errorf("bead: create tmp: %w", err)
418		}
419	
420		enc := json.NewEncoder(f)
421		enc.SetEscapeHTML(false)
422		for _, b := range beads {
423			data, err := marshalBead(b)
424			if err != nil {
425				f.Close()
426				os.Remove(tmp)
427				return fmt.Errorf("bead: marshal: %w", err)
428			}
429			if _, err := f.Write(data); err != nil {
430				f.Close()
431				os.Remove(tmp)
432				return fmt.Errorf("bead: write: %w", err)
433			}
434			if _, err := f.WriteString("\n"); err != nil {
435				f.Close()
436				os.Remove(tmp)
437				return fmt.Errorf("bead: write newline: %w", err)
438			}
439		}
440	
441		if err := f.Sync(); err != nil {
442			f.Close()
443			os.Remove(tmp)
444			return fmt.Errorf("bead: sync tmp: %w", err)
445		}
446		if err := f.Close(); err != nil {
447			os.Remove(tmp)
448			return fmt.Errorf("bead: close tmp: %w", err)
449		}
450		if err := os.Rename(tmp, s.File); err != nil {
451			os.Remove(tmp)
452			return fmt.Errorf("bead: rename tmp: %w", err)
453		}
454		return nil
455	}
