457	// Create adds a new bead. Assigns defaults, validates, then persists.
458	func (s *Store) Create(b *Bead) error {
459		now := time.Now().UTC()
460		if b.ID == "" {
461			id, err := s.GenID()
462			if err != nil {
463				return err
464			}
465			b.ID = id
466		}
467		if b.IssueType == "" {
468			b.IssueType = DefaultType
469		}
470		if b.Status == "" {
471			b.Status = DefaultStatus
472		}
473		b.CreatedAt = now
474		b.UpdatedAt = now
475	
476		// Validate after defaults are applied so hooks see final state
477		if err := s.validateBead(b); err != nil {
478			return err
479		}
480		// Story 15: an operator-prompt bead's execution may not create another
481		// operator-prompt bead. The execute-bead harness exports the actor's
482		// issue_type via DDX_ACTOR_ISSUE_TYPE; absent the env, the guard is a
483		// no-op (e.g. direct CLI use by a human operator).
484		if err := OperatorPromptMutationGuard(os.Getenv("DDX_ACTOR_ISSUE_TYPE"), b.IssueType); err != nil {
485			return err
486		}
487		// Run create hook
488		if err := s.runHook("validate-bead-create", b); err != nil {
489			return err
490		}
491	
492		return s.WithLock(func() error {
493			beads, _, err := s.readAllLatestRaw()
494			if err != nil {
495				return err
496			}
497			// Reject duplicate IDs
498			for _, e := range beads {
499				if e.ID == b.ID {
500					return fmt.Errorf("bead: duplicate id: %s", b.ID)
501				}
502			}
503			// Validate deps reference existing beads
504			depIDs := b.DepIDs()
505			if len(depIDs) > 0 {
506				existing := make(map[string]bool)
507				for _, e := range beads {
508					existing[e.ID] = true
509				}
510				for _, dep := range depIDs {
511					if !existing[dep] {
512						return fmt.Errorf("bead: dependency not found: %s", dep)
513					}
514				}
515			}
516			beads = append(beads, *b)
517			return s.WriteAll(beads)
518		})
519	}
