1192	// Reopen sets a bead's status back to open, clears claim fields, optionally
1193	// appends notes, and records an immutable reopen event — all in one atomic
1194	// lock acquisition.
1195	func (s *Store) Reopen(id string, reason string, appendNotes string) error {
1196		now := time.Now().UTC()
1197		return s.WithLock(func() error {
1198			beads, _, err := s.readAllLatestRaw()
1199			if err != nil {
1200				return err
1201			}
1202			found := false
1203			for i := range beads {
1204				if beads[i].ID != id {
1205					continue
1206				}
1207				b := &beads[i]
1208				b.Status = StatusOpen
1209				b.Owner = ""
1210				b.UpdatedAt = now
1211				if b.Extra == nil {
1212					b.Extra = make(map[string]any)
1213				}
1214				// Clear claim fields
1215				delete(b.Extra, "claimed-at")
1216				delete(b.Extra, "claimed-pid")
1217				delete(b.Extra, "claimed-machine")
1218				delete(b.Extra, "claimed-session")
1219				delete(b.Extra, "claimed-worktree")
1220				delete(b.Extra, "execute-loop-heartbeat-at")
1221				// Append notes
1222				if appendNotes != "" {
1223					if b.Notes != "" {
1224						b.Notes = b.Notes + "\n\n" + appendNotes
1225					} else {
1226						b.Notes = appendNotes
1227					}
1228				}
1229				// Record reopen event. If events were externalized at close,
1230				// pull them back inline so the active row carries the full
1231				// history again and the attachment ref is dropped.
1232				if hasEventsAttachment(b) {
1233					if err := s.inlineEventsInPlace(b); err != nil {
1234						return err
1235					}
1236					_ = os.Remove(s.eventsAttachmentPath(b.ID))
1237				}
1238				var events []BeadEvent
1239				if raw, ok := b.Extra["events"]; ok {
1240					events = decodeBeadEvents(raw)
1241				}
1242				evt := BeadEvent{
1243					Kind:      "reopen",
1244					CreatedAt: now,
1245				}
1246				if reason != "" {
1247					evt.Summary = reason
1248				}
1249				events = append(events, evt)
1250				encoded := make([]map[string]any, 0, len(events))
1251				for _, e := range events {
1252					encoded = append(encoded, map[string]any{
1253						"kind":       e.Kind,
1254						"summary":    e.Summary,
1255						"body":       e.Body,
1256						"actor":      e.Actor,
1257						"created_at": e.CreatedAt,
1258						"source":     e.Source,
1259					})
1260				}
1261				b.Extra["events"] = encoded
1262				if err := s.validateBead(b); err != nil {
1263					return err
1264				}
1265				if err := s.runHook("validate-bead-update", b); err != nil {
1266					return err
1267				}
1268				found = true
1269				break
1270			}
1271			if !found {
1272				return fmt.Errorf("bead: not found: %s", id)
1273			}
1274			if err := s.WriteAll(beads); err != nil {
1275				return err
1276			}
1277			return s.RemoveClaimHeartbeat(id)
1278		})
1279	}
