1305	// matchesWhere returns true if the bead satisfies all key=value predicates.
1306	// It checks known struct fields first, then falls back to Extra.
1307	func matchesWhere(b Bead, where map[string]string) bool {
1308		for k, v := range where {
1309			var actual string
1310			switch k {
1311			case "id":
1312				actual = b.ID
1313			case "title":
1314				actual = b.Title
1315			case "status":
1316				actual = b.Status
1317			case "issue_type":
1318				actual = b.IssueType
1319			case "owner":
1320				actual = b.Owner
1321			case "assignee":
1322				actual = b.Owner
1323			case "parent":
1324				actual = b.Parent
1325			case "description":
1326				actual = b.Description
1327			case "acceptance":
1328				actual = b.Acceptance
1329			case "notes":
1330				actual = b.Notes
1331			default:
1332				// Fall back to Extra map for unknown/workflow-specific fields
1333				if b.Extra != nil {
1334					if ev, ok := b.Extra[k]; ok {
1335						actual = fmt.Sprintf("%v", ev)
1336					}
1337				}
1338			}
1339			if actual != v {
1340				return false
1341			}
1342		}
1343		return true
1344	}
