1527	// Blocked returns open beads with at least one unclosed dependency.
1528	func (s *Store) Blocked() ([]Bead, error) {
1529		beads, err := s.ReadAll()
1530		if err != nil {
1531			return nil, err
1532		}
1533		statusMap := make(map[string]string)
1534		for _, b := range beads {
1535			statusMap[b.ID] = b.Status
1536		}
1537	
1538		var blocked []Bead
1539		for _, b := range beads {
1540			if b.Status != StatusOpen {
1541				continue
1542			}
1543			for _, depID := range b.DepIDs() {
1544				if statusMap[depID] != StatusClosed {
1545					blocked = append(blocked, b)
1546					break
1547				}
1548			}
1549		}
1550		sortBeadsForQueue(blocked)
1551		return blocked, nil
1552	}
1553	
1554	// BlockedAll returns open beads that are currently not runnable, classified
1555	// by blocker kind. Dependency-blocked beads are emitted first (any unclosed
1556	// dep in their DAG); retry-parked beads whose execute-loop-retry-after is in
1557	// the future are emitted with blocker kind BlockerKindRetryCooldown. A bead
1558	// that is both dep-blocked and cooldown-parked is reported as dependency-
1559	// blocked, because deps are the stronger blocker.
1560	func (s *Store) BlockedAll() ([]BlockedBead, error) {
1561		beads, err := s.ReadAll()
1562		if err != nil {
1563			return nil, err
1564		}
1565		statusMap := make(map[string]string)
1566		childCount := make(map[string]int)
1567		for _, b := range beads {
1568			statusMap[b.ID] = b.Status
1569			if b.Parent != "" {
1570				childCount[b.Parent]++
1571			}
1572		}
1573	
1574		now := time.Now().UTC()
1575		var entries []BlockedBead
1576		for _, b := range beads {
1577			if b.Status != StatusOpen && b.Status != StatusBlocked {
1578				continue
1579			}
1580	
1581			var unclosed []string
1582			for _, depID := range b.DepIDs() {
1583				if statusMap[depID] != StatusClosed {
1584					unclosed = append(unclosed, depID)
1585				}
1586			}
1587			if len(unclosed) > 0 {
1588				entries = append(entries, BlockedBead{
1589					Bead: b,
1590					Blocker: Blocker{
1591						Kind:           BlockerKindDependency,
1592						UnclosedDepIDs: unclosed,
1593					},
1594				})
1595				continue
1596			}
1597			if b.Status == StatusBlocked {
1598				entries = append(entries, BlockedBead{
1599					Bead: b,
1600					Blocker: Blocker{
1601						Kind:   BlockerKindBlockedStatus,
1602						Reason: "persisted blocked status",
1603					},
1604				})
1605				continue
1606			}
1607	
1608			if hasLabel(b, LabelNeedsInvestigation) || hasLabel(b, LabelNeedsHuman) {
1609				entries = append(entries, BlockedBead{
1610					Bead: b,
1611					Blocker: Blocker{
1612						Kind:       BlockerKindNeedsInvestigation,
1613						LastStatus: "no_changes",
1614						Reason:     "triage needs investigation before retry",
1615					},
1616				})
1617				continue
1618			}
1619			if isOrdinaryEpicContainer(b, childCount[b.ID]) {
1620				entries = append(entries, BlockedBead{
1621					Bead: b,
1622					Blocker: Blocker{
1623						Kind:   BlockerKindEpicOnly,
1624						Reason: "ordinary ddx work skips epic/container beads",
1625					},
1626				})
1627				continue
1628			}
1629	
1630			if eligible, ok := b.Extra["execution-eligible"]; ok {
1631				if val, isBool := eligible.(bool); isBool && !val {
1632					reason, _ := b.Extra["execution-skip-reason"].(string)
1633					entries = append(entries, BlockedBead{
1634						Bead: b,
1635						Blocker: Blocker{
1636							Kind:   BlockerKindNotEligible,
1637							Reason: reason,
1638						},
1639					})
1640					continue
1641				}
1642			}
1643			if sup, ok := b.Extra["superseded-by"]; ok {
1644				if s, isStr := sup.(string); isStr && s != "" {
1645					entries = append(entries, BlockedBead{
1646						Bead: b,
1647						Blocker: Blocker{
1648							Kind:   BlockerKindSuperseded,
1649							Reason: s,
1650						},
1651					})
1652					continue
1653				}
1654			}
1655	
1656			retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]
1657			if !ok {
1658				continue
1659			}
1660			retryAfterStr, isStr := retryAfterRaw.(string)
1661			if !isStr || retryAfterStr == "" {
1662				continue
1663			}
1664			retryAfter, err := time.Parse(time.RFC3339, retryAfterStr)
1665			if err != nil || !retryAfter.After(now) {
1666				continue
1667			}
1668			blocker := Blocker{
1669				Kind:           BlockerKindRetryCooldown,
1670				NextEligibleAt: retryAfter.UTC().Format(time.RFC3339),
1671			}
1672			if v, ok := b.Extra["execute-loop-last-status"]; ok {
1673				if s, ok := v.(string); ok {
1674					blocker.LastStatus = s
1675				}
1676			}
1677			if v, ok := b.Extra["execute-loop-last-detail"]; ok {
1678				if s, ok := v.(string); ok {
1679					blocker.LastDetail = s
1680				}
1681			}
1682			entries = append(entries, BlockedBead{
1683				Bead:    b,
1684				Blocker: blocker,
1685			})
1686		}
1687	
1688		sort.SliceStable(entries, func(i, j int) bool {
1689			if entries[i].Priority != entries[j].Priority {
1690				return entries[i].Priority < entries[j].Priority
1691			}
1692			if !entries[i].CreatedAt.Equal(entries[j].CreatedAt) {
1693				return entries[i].CreatedAt.Before(entries[j].CreatedAt)
1694			}
1695			return entries[i].ID < entries[j].ID
1696		})
1697		return entries, nil
1698	}
1699	
1700	func depsSatisfied(b Bead, statusMap map[string]string) bool {
1701		for _, depID := range b.DepIDs() {
1702			if statusMap[depID] != StatusClosed {
1703				return false
1704			}
1705		}
1706		return true
1707	}
1708	
1709	func isOrdinaryEpicContainer(b Bead, childCount int) bool {
1710		issueType := strings.ToLower(strings.TrimSpace(b.IssueType))
1711		title := strings.ToLower(strings.TrimSpace(b.Title))
1712		return issueType == "epic" || strings.HasPrefix(title, "epic:") || (childCount > 0 && strings.HasPrefix(title, "epic "))
1713	}
1714	
1715	func isEpicClosureCandidate(b Bead, childCount, openChildCount int) bool {
1716		if childCount == 0 {
1717			return false
1718		}
1719		return isOrdinaryEpicContainer(b, childCount) && openChildCount == 0
1720	}
1721	
1722	func sortBeadsForQueue(beads []Bead) {
1723		sort.SliceStable(beads, func(i, j int) bool {
1724			if beads[i].Priority != beads[j].Priority {
1725				return beads[i].Priority < beads[j].Priority
1726			}
1727			ir, iok := parseQueueRank(beads[i].Extra["queue-rank"])
1728			jr, jok := parseQueueRank(beads[j].Extra["queue-rank"])
1729			if iok != jok {
1730				return iok
1731			}
1732			if iok && jok && ir != jr {
1733				return ir < jr
1734			}
1735			if !beads[i].CreatedAt.Equal(beads[j].CreatedAt) {
1736				return beads[i].CreatedAt.Before(beads[j].CreatedAt)
1737			}
1738			return beads[i].ID < beads[j].ID
1739		})
1740	}
1741	
1742	func parseQueueRank(raw any) (int, bool) {
1743		switch v := raw.(type) {
1744		case int:
1745			return v, true
1746		case int8:
1747			return int(v), true
1748		case int16:
1749			return int(v), true
1750		case int32:
1751			return int(v), true
1752		case int64:
1753			return int(v), true
1754		case uint:
1755			return int(v), true
1756		case uint8:
1757			return int(v), true
1758		case uint16:
1759			return int(v), true
1760		case uint32:
1761			return int(v), true
1762		case uint64:
1763			return int(v), true
1764		case float32:
1765			return int(v), v == float32(int(v))
1766		case float64:
1767			return int(v), v == float64(int(v))
1768		case json.Number:
1769			if n, err := v.Int64(); err == nil {
1770				return int(n), true
1771			}
1772			if f, err := v.Float64(); err == nil {
1773				return int(f), f == float64(int(f))
1774			}
1775		case string:
1776			if n, err := strconv.Atoi(strings.TrimSpace(v)); err == nil {
1777				return n, true
1778			}
1779		}
1780		return 0, false
1781	}
1782	
1783	// Status returns aggregate counts.
1784	func (s *Store) Status() (*StatusCounts, error) {
1785		beads, err := s.ReadAll()
1786		if err != nil {
1787			return nil, err
1788		}
1789		ready, err := s.Ready()
1790		if err != nil {
1791			return nil, err
1792		}
1793		blocked, err := s.Blocked()
1794		if err != nil {
1795			return nil, err
1796		}
1797	
1798		// Pull in archive partner so totals survive `bead migrate` — the archive
1799		// only carries closed beads, so Ready/Blocked aren't affected.
1800		seen := make(map[string]bool, len(beads))
1801		all := make([]Bead, 0, len(beads))
1802		for _, b := range beads {
1803			if seen[b.ID] {
1804				continue
1805			}
1806			seen[b.ID] = true
1807			all = append(all, b)
1808		}
1809		if s.Collection == DefaultCollection {
1810			archive := s.archivePartner()
1811			if archived, aerr := archive.ReadAll(); aerr == nil {
1812				for _, b := range archived {
1813					if seen[b.ID] {
1814						continue
1815					}
1816					seen[b.ID] = true
1817					all = append(all, b)
1818				}
1819			}
1820		}
1821	
1822		counts := &StatusCounts{Total: len(all), Ready: len(ready), Blocked: len(blocked)}
1823		for _, b := range all {
1824			switch b.Status {
1825			case StatusOpen:
1826				counts.Open++
1827			case StatusClosed:
1828				counts.Closed++
1829			}
1830		}
1831		return counts, nil
1832	}
1833	
1834	// DepAdd adds a dependency: id depends on depID.
1835	func (s *Store) DepAdd(id, depID string) error {
1836		return s.WithLock(func() error {
1837			beads, _, err := s.readAllLatestRaw()
1838			if err != nil {
1839				return err
1840			}
1841			var target *Bead
1842			depExists := false
1843			for i := range beads {
1844				if beads[i].ID == id {
1845					target = &beads[i]
1846				}
1847				if beads[i].ID == depID {
1848					depExists = true
1849				}
1850			}
1851			if target == nil {
1852				return fmt.Errorf("bead: not found: %s", id)
1853			}
1854			if !depExists {
1855				return fmt.Errorf("bead: dependency not found: %s", depID)
1856			}
1857			if id == depID {
1858				return fmt.Errorf("bead: cannot depend on self")
1859			}
1860			if target.HasDep(depID) {
1861				return nil // already exists
1862			}
1863	
1864			// Check for circular dependency
1865			depMap := make(map[string][]string)
1866			for _, b := range beads {
1867				depMap[b.ID] = b.DepIDs()
1868			}
1869			depMap[id] = append(append([]string{}, target.DepIDs()...), depID)
1870			if hasCycle(depMap, id) {
1871				return fmt.Errorf("bead: circular dependency: %s -> %s", id, depID)
1872			}
1873	
1874			target.AddDep(depID, "blocks")
1875			target.UpdatedAt = time.Now().UTC()
1876			return s.WriteAll(beads)
1877		})
1878	}
1879	
1880	// DepRemove removes a dependency.
1881	func (s *Store) DepRemove(id, depID string) error {
1882		return s.Update(id, func(b *Bead) {
1883			b.RemoveDep(depID)
1884		})
1885	}
