1962	func (s *Store) printTree(sb *strings.Builder, byID map[string]*Bead, id, prefix string, last bool) {
1963		b, ok := byID[id]
1964		if !ok {
1965			return
1966		}
1967	
1968		connector := "├── "
1969		if last {
1970			connector = "└── "
1971		}
1972		if prefix == "" {
1973			connector = ""
1974		}
1975	
1976		fmt.Fprintf(sb, "%s%s%s [%s] %s\n", prefix, connector, b.ID, b.Status, b.Title)
1977	
1978		// Find beads that depend on this one (children in the tree)
1979		var children []string
1980		for _, other := range sortedKeys(byID) {
1981			if byID[other].HasDep(id) {
1982				children = append(children, other)
1983			}
1984		}
1985	
1986		childPrefix := prefix
1987		if prefix != "" {
1988			if last {
1989				childPrefix += "    "
1990			} else {
1991				childPrefix += "│   "
1992			}
1993		}
1994	
1995		for i, child := range children {
1996			s.printTree(sb, byID, child, childPrefix, i == len(children)-1)
1997		}
1998	}
