313	func noChangesCount(b Bead) int {
314		if b.Extra == nil {
315			return 0
316		}
317		switch v := b.Extra[ExtraNoChangesCount].(type) {
318		case int:
319			return v
320		case int64:
321			return int(v)
322		case float64:
323			return int(v)
324		}
325		return 0
326	}
