457	// Create adds a new bead. Assigns defaults, validates, then persists.
458	func (s *Store) Create(b *Bead) error {
459		now := time.Now().UTC()
460		if b.ID == "" {
461			id, err := s.GenID()
462			if err != nil {
463				return err
464			}
465			b.ID = id
466		}
467		if b.IssueType == "" {
468			b.IssueType = DefaultType
469		}
470		if b.Status == "" {
471			b.Status = DefaultStatus
472		}
473		b.CreatedAt = now
474		b.UpdatedAt = now
475	
476		// Validate after defaults are applied so hooks see final state
477		if err := s.validateBead(b); err != nil {
478			return err
479		}
480		// Story 15: an operator-prompt bead's execution may not create another
481		// operator-prompt bead. The execute-bead harness exports the actor's
482		// issue_type via DDX_ACTOR_ISSUE_TYPE; absent the env, the guard is a
483		// no-op (e.g. direct CLI use by a human operator).
484		if err := OperatorPromptMutationGuard(os.Getenv("DDX_ACTOR_ISSUE_TYPE"), b.IssueType); err != nil {
485			return err
486		}
487		// Run create hook
488		if err := s.runHook("validate-bead-create", b); err != nil {
489			return err
490		}
491	
492		return s.WithLock(func() error {
493			beads, _, err := s.readAllLatestRaw()
494			if err != nil {
495				return err
496			}
497			// Reject duplicate IDs
498			for _, e := range beads {
499				if e.ID == b.ID {
500					return fmt.Errorf("bead: duplicate id: %s", b.ID)
501				}
502			}
503			// Validate deps reference existing beads
504			depIDs := b.DepIDs()
505			if len(depIDs) > 0 {
506				existing := make(map[string]bool)
507				for _, e := range beads {
508					existing[e.ID] = true
509				}
510				for _, dep := range depIDs {
511					if !existing[dep] {
512						return fmt.Errorf("bead: dependency not found: %s", dep)
513					}
514				}
515			}
516			beads = append(beads, *b)
517			return s.WriteAll(beads)
518		})
519	}
520	
521	// Get retrieves a bead by ID.
522	func (s *Store) Get(id string) (*Bead, error) {
523		beads, err := s.ReadAll()
524		if err != nil {
525			return nil, err
526		}
527		for _, b := range beads {
528			if b.ID == id {
529				return &b, nil
530			}
531		}
532		return nil, fmt.Errorf("bead: not found: %s", id)
533	}
534	
535	// Update modifies a bead by ID. The mutate function receives a pointer to modify.
536	func (s *Store) Update(id string, mutate func(*Bead)) error {
537		return s.WithLock(func() error {
538			beads, _, err := s.readAllLatestRaw()
539			if err != nil {
540				return err
541			}
542			found := false
543			for i := range beads {
544				if beads[i].ID == id {
545					mutate(&beads[i])
546					beads[i].UpdatedAt = time.Now().UTC()
547					// Core validation after mutation
548					if err := s.validateBead(&beads[i]); err != nil {
549						return err
550					}
551					// Run update hook
552					if err := s.runHook("validate-bead-update", &beads[i]); err != nil {
553						return err
554					}
555					found = true
556					break
557				}
558			}
559			if !found {
560				return fmt.Errorf("bead: not found: %s", id)
561			}
562			return s.WriteAll(beads)
563		})
564	}
565	
566	// HeartbeatInterval is how often a claim owner should refresh the external
567	// claim liveness lease while running. Exposed as a variable so tests can
568	// override it.
569	var HeartbeatInterval = 30 * time.Second
570	
571	// HeartbeatTTL is the maximum allowed age of the external claim liveness
572	// lease before another worker may reclaim the bead. Defaults to 3×
573	// HeartbeatInterval. Exposed as a variable so tests can override it.
574	var HeartbeatTTL = 90 * time.Second
575	
576	// Claim sets a bead to in_progress with claim metadata.
577	// Fails if the bead is already claimed (status == in_progress) with a
578	// fresh claim lease. A bead whose external lease is older than HeartbeatTTL
579	// is considered stalled and will be reclaimed atomically.
580	func (s *Store) Claim(id, assignee string) error {
581		return s.ClaimWithOptions(id, assignee, "", "")
582	}
583	
584	// ClaimWithOptions sets a bead to in_progress with extended claim metadata.
585	// session and worktree are optional; machine is derived from os.Hostname().
586	// A stalled in_progress bead (external lease older than HeartbeatTTL) is
587	// reclaimed atomically under the store's lock.
588	func (s *Store) ClaimWithOptions(id, assignee, session, worktree string) error {
589		machine, _ := os.Hostname()
590		if envID := os.Getenv("DDX_MACHINE_ID"); envID != "" {
591			machine = envID
592		}
593		return s.WithLock(func() error {
594			beads, _, err := s.readAllLatestRaw()
595			if err != nil {
596				return err
597			}
598			for i := range beads {
599				if beads[i].ID != id {
600					continue
601				}
602				switch beads[i].Status {
603				case StatusOpen:
604					// normal claim path
605				case StatusInProgress:
606					if !claimLeaseIsStale(s, beads[i].Extra, id) {
607						return fmt.Errorf("bead: cannot claim %s from status %s", id, beads[i].Status)
608					}
609					// stalled claim — reclaim atomically below
610				default:
611					return fmt.Errorf("bead: cannot claim %s from status %s", id, beads[i].Status)
612				}
613				// Refuse claims on beads parked with last_status=push_failed:
614				// the previous attempt landed locally but `git push` was rejected,
615				// so the local commit history exists only on this machine. Re-running
616				// primary work would duplicate or strand commits. The operator must
617				// clear execute-loop-last-status (e.g. by manually pushing or
618				// resetting) before another attempt is allowed.
619				if last, ok := beads[i].Extra["execute-loop-last-status"].(string); ok && last == "push_failed" {
620					detail, _ := beads[i].Extra["execute-loop-last-detail"].(string)
621					if detail != "" {
622						return fmt.Errorf("bead: refusing to claim %s — previous attempt landed locally but push failed (%s); clear execute-loop-last-status to retry", id, detail)
623					}
624					return fmt.Errorf("bead: refusing to claim %s — previous attempt landed locally but push failed; clear execute-loop-last-status to retry", id)
625				}
626				if beads[i].Extra == nil {
627					beads[i].Extra = make(map[string]any)
628				}
629				now := time.Now().UTC()
630				beads[i].Status = StatusInProgress
631				beads[i].Owner = assignee
632				beads[i].UpdatedAt = now
633				beads[i].Extra["claimed-at"] = now.Format(time.RFC3339)
634				beads[i].Extra["claimed-pid"] = fmt.Sprintf("%d", os.Getpid())
635				beads[i].Extra["execute-loop-heartbeat-at"] = now.Format(time.RFC3339Nano)
636				if machine != "" {
637					beads[i].Extra["claimed-machine"] = machine
638				}
639				if session != "" {
640					beads[i].Extra["claimed-session"] = session
641				}
642				if worktree != "" {
643					beads[i].Extra["claimed-worktree"] = worktree
644				}
645				if err := s.validateBead(&beads[i]); err != nil {
646					return err
647				}
648				if err := s.runHook("validate-bead-update", &beads[i]); err != nil {
649					return err
650				}
651				if err := s.WriteAll(beads); err != nil {
652					return err
653				}
654				return s.TouchClaimHeartbeat(id)
655			}
656			return fmt.Errorf("bead: not found: %s", id)
657		})
658	}
