794	// MaxFieldBytes is the per-field hard cap on bead event bodies and adjacent
795	// writer paths. 65,535 bytes matches upstream bd's Dolt TEXT column size so
796	// DDx-authored beads always round-trip through `bd import`. Empirically
797	// validated against bd 1.0.2 on 2026-04-20: 65,535 accepts, 65,536 rejects.
798	const MaxFieldBytes = 65535
799	
800	// capFieldBytes enforces MaxFieldBytes on a single field value. Callers that
801	// need to preserve the full payload should persist it to a sidecar artifact
802	// and store a path reference in the field; this function is the defense-in-
803	// depth cap for code paths that don't. Returns the input unchanged when it
804	// fits; otherwise returns head+tail truncation with a byte-count marker.
805	func capFieldBytes(s string) string {
806		if len(s) <= MaxFieldBytes {
807			return s
808		}
809		// Reserve a marker that always fits; keep head heavy (2/3) so
810		// human-readable context is preserved for the common short-rationale case.
811		marker := fmt.Sprintf("\n…[truncated, %d bytes]\n", len(s))
812		budget := MaxFieldBytes - len(marker)
813		if budget <= 0 {
814			return s[:MaxFieldBytes]
815		}
816		head := (budget * 2) / 3
817		tail := budget - head
818		return s[:head] + marker + s[len(s)-tail:]
819	}
