821	// Cancel-marker keys on Bead.Extra. ADR-022 §Cancel SLA: an operator-initiated
822	// cancel writes cancel-requested:true; the worker that honors the cancel writes
823	// cancel-honored:true alongside it.
824	const (
825		ExtraCancelRequested = "cancel-requested"
826		ExtraCancelHonored   = "cancel-honored"
827	)
828	
829	// RequestCancel writes Extra[cancel-requested]=true on the bead. Idempotent:
830	// if cancel-honored is already set the call is a silent no-op (the prior cancel
831	// was already consumed). Returns true when the marker is now set on the bead
832	// (either by this call or a prior one).
833	func (s *Store) RequestCancel(id string) (bool, error) {
834		var set bool
835		err := s.Update(id, func(b *Bead) {
836			if b.Extra == nil {
837				b.Extra = make(map[string]any)
838			}
839			if isExtraTrue(b.Extra[ExtraCancelHonored]) {
840				set = isExtraTrue(b.Extra[ExtraCancelRequested])
841				return
842			}
843			b.Extra[ExtraCancelRequested] = true
844			set = true
845		})
846		return set, err
847	}
848	
849	// IsCancelRequested reports whether the bead carries an unconsumed cancel
850	// marker (cancel-requested:true and cancel-honored not yet set).
851	func (s *Store) IsCancelRequested(id string) (bool, error) {
852		b, err := s.Get(id)
853		if err != nil {
854			return false, err
855		}
856		if b == nil || b.Extra == nil {
857			return false, nil
858		}
859		if isExtraTrue(b.Extra[ExtraCancelHonored]) {
860			return false, nil
861		}
862		return isExtraTrue(b.Extra[ExtraCancelRequested]), nil
863	}
864	
865	// MarkCancelHonored sets Extra[cancel-honored]=true. Called by the worker once
866	// it has aborted at the next safe point in response to a cancel request.
867	func (s *Store) MarkCancelHonored(id string) error {
868		return s.Update(id, func(b *Bead) {
869			if b.Extra == nil {
870				b.Extra = make(map[string]any)
871			}
872			b.Extra[ExtraCancelHonored] = true
873		})
874	}
