1038	// externalizeEvents moves a bead's inline events into its sidecar attachment
1039	// under a fresh lock. Safe to call repeatedly — no-op when there are no
1040	// inline events (already externalized, or none recorded).
1041	func (s *Store) externalizeEvents(id string) error {
1042		if s.axonGraphQLActive() {
1043			return nil
1044		}
1045		return s.WithLock(func() error {
1046			beads, _, err := s.readAllLatestRaw()
1047			if err != nil {
1048				return err
1049			}
1050			for i := range beads {
1051				if beads[i].ID != id {
