1063	// ErrClosureGateRejected indicates a close was refused because the bead does
1064	// not carry the evidence required for an automated closure: a terminal
1065	// verdict event (review APPROVE with non-empty rationale, or an explicit
1066	// review-skipped / manual-close marker) AND an execution-evidence marker
1067	// (closing_commit_sha, session_id, or an execute-bead success event in the
1068	// events history).
1069	//
1070	// Automated execute-loop paths (execute-bead + reviewer) always go through
1071	// CloseWithEvidence. The plain Store.Close remains as the manual
1072	// administration escape hatch — it bypasses the gate by design (ddx-e30e60a9
1073	// acceptance §1).
1074	var ErrClosureGateRejected = fmt.Errorf("closure gate: insufficient evidence")
1075	
1076	// ClosureGate inspects a bead and returns nil iff the close is safe. It
1077	// rejects only the specific shapes that caused the 2026-04-18/20
1078	// review-malfunction incidents:
1079	//
1080	//  1. axon-c5cc071a (silent false-closure): closed with no events AND no
1081	//     closing_commit_sha. Rejected by the execution-evidence check —
1082	//     closing_commit_sha must be non-empty OR at least one event must exist.
1083	//  2. f7ae036f (broken APPROVE): a review event with summary=APPROVE whose
1084	//     body is empty. Rejected — APPROVE with no rationale is exactly the
1085	//     parse-mis-extract shape the reviewer bug produced.
1086	//
1087	// Beads without a review step (--no-review, no Reviewer configured, already-
1088	// satisfied paths) pass the gate as long as they carry execution evidence.
1089	// This keeps the surface small: the gate catches known-bad shapes, not every
1090	// conceivable edge case. Additional invariants belong in future dedicated
1091	// beads so the rejection reason stays auditable.
1092	func ClosureGate(b *Bead) error {
1093		if b == nil {
1094			return fmt.Errorf("%w: nil bead", ErrClosureGateRejected)
1095		}
1096		hasClosingCommit := false
1097		if sha, ok := b.Extra["closing_commit_sha"].(string); ok && strings.TrimSpace(sha) != "" {
1098			hasClosingCommit = true
1099		}
1100		events := decodeBeadEvents(b.Extra["events"])
1101		// Externalized events still count as evidence for the gate. We only need
1102		// to know whether *some* event history exists, not iterate it; the
1103		// gate's APPROVE-with-empty-rationale check below relies on inline events
1104		// (the verdict is recorded before externalization).
1105		hasAttachedEvents := hasEventsAttachment(b)
1106		// Reject the axon-c5cc071a shape: no events AND no closing commit.
1107		if len(events) == 0 && !hasAttachedEvents && !hasClosingCommit {
1108			return fmt.Errorf("%w: no execution evidence (empty events and no closing_commit_sha)", ErrClosureGateRejected)
1109		}
1110		// Reject the f7ae036f shape: an APPROVE verdict with empty rationale.
1111		for _, e := range events {
1112			if e.Kind == "review" && strings.EqualFold(strings.TrimSpace(e.Summary), "APPROVE") {
1113				if strings.TrimSpace(e.Body) == "" {
1114					return fmt.Errorf("%w: review APPROVE with empty rationale (malformed reviewer verdict)", ErrClosureGateRejected)
1115				}
1116			}
1117		}
1118		return nil
1119	}
