2009	// validateBead checks core invariants that must hold for any bead (create or update).
2010	func (s *Store) validateBead(b *Bead) error {
2011		if strings.TrimSpace(b.Title) == "" {
2012			return fmt.Errorf("bead: title is required")
2013		}
2014		if b.Priority < MinPriority || b.Priority > MaxPriority {
2015			return fmt.Errorf("bead: priority must be %d-%d, got %d", MinPriority, MaxPriority, b.Priority)
2016		}
2017		if !IsCanonicalStatus(b.Status) {
2018			return fmt.Errorf("bead: invalid status: %s", b.Status)
2019		}
2020		// Self-ref check
2021		for _, depID := range b.DepIDs() {
2022			if depID == b.ID && b.ID != "" {
2023				return fmt.Errorf("bead: cannot depend on self")
2024			}
2025		}
2026		return nil
2027	}
2028	
2029	// detectPrefix derives the bead ID prefix from the repository/directory name,
2030	// following the bd convention (e.g., repo "my-project" → prefix "my-project").
2031	// workingDir is the project root to use for git commands; when empty the
2032	// process working directory is used (legacy behaviour, prone to worktree
2033	// path contamination). Falls back to DefaultPrefix if detection fails.
2034	func detectPrefix(workingDir string) string {
2035		// Try git repo root name first, running from the known project root so
2036		// that linked worktrees (e.g. execute-bead isolated worktrees) do not
2037		// contaminate the prefix with their ephemeral directory names.
2038		cmd := gitpkg.Command(context.Background(), workingDir, "rev-parse", "--show-toplevel")
2039		if out, err := cmd.Output(); err == nil {
2040			root := strings.TrimSpace(string(out))
2041			if root != "" {
2042				return filepath.Base(root)
2043			}
2044		}
2045		// Fall back to the provided working dir, then cwd.
2046		if workingDir != "" {
2047			return filepath.Base(workingDir)
2048		}
2049		if wd, err := os.Getwd(); err == nil {
2050			return filepath.Base(wd)
2051		}
2052		return DefaultPrefix
2053	}
2054	
2055	func parseDurationOr(envKey string, fallback time.Duration) time.Duration {
2056		v := os.Getenv(envKey)
2057		if v == "" {
2058			return fallback
2059		}
2060		// Try as seconds (plain number)
2061		if secs, err := strconv.ParseFloat(v, 64); err == nil {
2062			return time.Duration(secs * float64(time.Second))
2063		}
2064		// Try as Go duration
2065		if d, err := time.ParseDuration(v); err == nil {
2066			return d
2067		}
2068		return fallback
2069	}
2070	
2071	func envOr(key, fallback string) string {
2072		if v := os.Getenv(key); v != "" {
2073			return v
2074		}
2075		return fallback
2076	}
2077	
2078	func containsString(ss []string, s string) bool {
2079		for _, v := range ss {
2080			if v == s {
2081				return true
2082			}
2083		}
2084		return false
2085	}
2086	
2087	func sortedKeys(m map[string]*Bead) []string {
2088		keys := make([]string, 0, len(m))
2089		for k := range m {
2090			keys = append(keys, k)
2091		}
2092		sort.Strings(keys)
2093		return keys
2094	}
2095	
2096	// hasCycle detects cycles in the dependency graph starting from startID.
2097	func hasCycle(deps map[string][]string, startID string) bool {
2098		visited := make(map[string]bool)
2099		stack := make(map[string]bool)
2100	
2101		var visit func(string) bool
2102		visit = func(id string) bool {
2103			visited[id] = true
2104			stack[id] = true
2105	
2106			for _, dep := range deps[id] {
2107				if !visited[dep] {
2108					if visit(dep) {
2109						return true
2110					}
2111				} else if stack[dep] {
2112					return true
2113				}
2114			}
2115	
2116			stack[id] = false
2117			return false
2118		}
2119	
2120		return visit(startID)
2121	}
