44	func beadConnectionFromSnapshots(snaps []BeadSnapshot, first *int, after *string, last *int, before *string) *BeadConnection {
45		// Build full edge list with stable ID-based cursors.
46		all := make([]*BeadEdge, len(snaps))
47		for i, s := range snaps {
48			all[i] = &BeadEdge{
49				Node:   beadFromSnapshot(s),
50				Cursor: encodeStableCursor(s.ID),
51			}
52		}
53	
54		// Apply window: start after `after` cursor, end before `before` cursor.
55		startIdx := 0
56		if after != nil {
57			if afterID, ok := decodeStableCursor(*after); ok {
58				for i, e := range all {
59					if e.Node.ID == afterID {
60						startIdx = i + 1
61						break
62					}
63				}
64			}
65		}
66		endIdx := len(all)
67		if before != nil {
68			if beforeID, ok := decodeStableCursor(*before); ok {
69				for i, e := range all {
70					if e.Node.ID == beforeID {
71						endIdx = i
72						break
73					}
74				}
75			}
76		}
77		if startIdx > endIdx {
78			startIdx = endIdx
79		}
80	
81		slice := all[startIdx:endIdx]
82		truncatedByFirst := false
83		truncatedByLast := false
84		if first != nil && *first >= 0 && *first < len(slice) {
85			slice = slice[:*first]
86			truncatedByFirst = true
87		}
88		if last != nil && *last >= 0 && *last < len(slice) {
89			slice = slice[len(slice)-*last:]
90			truncatedByLast = true
91		}
92	
93		pageInfo := &PageInfo{
94			HasPreviousPage: startIdx > 0 || truncatedByLast,
95			HasNextPage:     endIdx < len(all) || truncatedByFirst,
96		}
97		if len(slice) > 0 {
98			pageInfo.StartCursor = &slice[0].Cursor
99			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
100		}
101	
102		return &BeadConnection{
103			Edges:      slice,
104			PageInfo:   pageInfo,
105			TotalCount: len(all),
106		}
107	}
108	
109	func beadFromSnapshot(s BeadSnapshot) *Bead {
110		b := &Bead{
111			ID:        s.ID,
112			Title:     s.Title,
113			Status:    s.Status,
114			Priority:  s.Priority,
115			IssueType: s.IssueType,
116			CreatedAt: s.CreatedAt.UTC().Format(time.RFC3339),
117			UpdatedAt: s.UpdatedAt.UTC().Format(time.RFC3339),
118			Labels:    s.Labels,
119		}
120		if s.ProjectID != "" {
121			b.ProjectID = &s.ProjectID
122		}
123		if s.Owner != "" {
124			b.Owner = &s.Owner
125		}
126		if s.CreatedBy != "" {
127			b.CreatedBy = &s.CreatedBy
128		}
129		if s.Parent != "" {
130			b.Parent = &s.Parent
131		}
132		if s.Description != "" {
133			b.Description = &s.Description
134		}
135		if s.Acceptance != "" {
136			b.Acceptance = &s.Acceptance
137		}
138		if s.Notes != "" {
139			b.Notes = &s.Notes
140		}
141		for _, d := range s.Dependencies {
142			dep := &Dependency{
143				IssueID:     d.IssueID,
144				DependsOnID: d.DependsOnID,
145				Type:        d.Type,
146			}
147			if d.CreatedAt != "" {
148				dep.CreatedAt = &d.CreatedAt
149			}
150			if d.CreatedBy != "" {
151				dep.CreatedBy = &d.CreatedBy
152			}
153			if d.Metadata != "" {
154				dep.Metadata = &d.Metadata
155			}
156			b.Dependencies = append(b.Dependencies, dep)
157		}
158		return b
159	}
