11		"github.com/DocumentDrivenDX/ddx/internal/bead"
12		"github.com/DocumentDrivenDX/ddx/internal/config"
13		"github.com/DocumentDrivenDX/ddx/internal/escalation"
14		"github.com/DocumentDrivenDX/ddx/internal/triage"
15	)
16	
17	// triageDecisionEventKind is the event kind used to record the triage
18	// policy's chosen action after a non-APPROVE review verdict.
19	const triageDecisionEventKind = "triage-decision"
20	
21	// PostMergeReviewInput bundles the data RunPostMergeReview needs from its
22	// caller — historically the execute-bead loop body, now the per-attempt
23	// pipeline owned by try.Attempt (ddx-a921ff01 C3). The fields mirror what
24	// the inlined block read from the worker, the candidate bead, the report,
25	// and the loop runtime.
26	type PostMergeReviewInput struct {
27		Bead          bead.Bead
28		Report        ExecuteBeadReport
29		Reviewer      BeadReviewer
30		Store         ExecuteBeadLoopStore
31		ProjectRoot   string
32		Rcfg          config.ResolvedConfig
33		NoReview      bool
34		Log           io.Writer
35		Assignee      string
36		Now           func() time.Time
37		ReviewCostCap *escalation.CostCapTracker
38	}
39	
40	// PostMergeReviewOutput carries the review state machine's decision back to
41	// the caller. Report is the (possibly updated) ExecuteBeadReport; Approved
42	// reports whether the caller should treat this attempt as a success. When
43	// the review path encountered a non-fatal Store error the caller is expected
44	// to route StoreErr through its outcome-error handler
45	// (handleOutcomeStoreError on ExecuteBeadWorker), keyed by StoreErrOp.
46	type PostMergeReviewOutput struct {
47		Report     ExecuteBeadReport
48		Approved   bool
49		StoreErrOp string
50		StoreErr   error
51	}
52	
53	// RunPostMergeReview executes the post-merge review state machine for a
54	// successful bead attempt. When review is skipped (no reviewer or --no-review)
55	// the bead is closed and the function returns Approved=true. When review is
56	// active, the execute-loop asks the review coordinator to evaluate the
57	// close-eligible result before CloseWithEvidence runs; close only proceeds on
58	// unanimous evidence-backed APPROVE. REQUEST_CHANGES and BLOCK record their
59	// review events without reopening the bead.
60	//
61	// The review:skip label only skips when it carries a sibling
62	// review:skip-reason:* label; otherwise it is ignored. When review is not
63	// skipped, the review coordinator's verdict(s) or error drive the canonical
64	// event emissions (review / review-error / review-manual-required /
65	// review-malfunction), and on a non-APPROVE verdict the triage policy is
66	// still consulted without reopening the bead.
67	//
68	// Returns Approved=true on the APPROVE path and on the skip path; returns
69	// Approved=false on REQUEST_CHANGES, BLOCK, malformed APPROVE/BLOCK, or
70	// reviewer transport error. Store errors are surfaced via StoreErrOp +
71	// StoreErr so callers can keep the existing handleOutcomeStoreError pattern
72	// unchanged.
73	//
74	// This is the C3 (ddx-a921ff01) extraction of the 180-line review block
75	// previously inline in execute_bead_loop.go; the loop now sees a structured
76	// outcome and conflict-recovery / decomposition / no_changes paths remain
77	// in the loop body until subsequent C-series beads (C4, C5) move them too.
78	func RunPostMergeReview(ctx context.Context, in PostMergeReviewInput) PostMergeReviewOutput {
79		report := in.Report
80		out := PostMergeReviewOutput{Report: report, Approved: true}
81	
82		now := in.Now
83		if now == nil {
84			now = time.Now
85		}
86	
87		reviewSkipped := in.Reviewer == nil || in.NoReview
88		if !reviewSkipped && HasBeadLabel(in.Bead.Labels, "review:skip") {
89			reviewSkipped = HasBeadLabelPrefix(in.Bead.Labels, "review:skip-reason:")
90		}
91	
92		if reviewSkipped {
93			if err := in.Store.CloseWithEvidence(in.Bead.ID, report.SessionID, report.ResultRev); err != nil {
94				out.StoreErrOp = "CloseWithEvidence"
95				out.StoreErr = err
96				return out
97			}
98			out.Report = report
99			return out
100		}
101	
102		implRouting := ImplementerRouting{
103			Harness:     report.Harness,
104			Provider:    report.Provider,
105			Model:       report.Model,
106			ActualPower: report.ActualPower,
107			Correlation: map[string]string{
108				"bead_id":    in.Bead.ID,
109				"attempt_id": report.AttemptID,
110				"session_id": report.SessionID,
111				"result_rev": report.ResultRev,
112			},
113		}
114		reviewGroup, reviewErr := runPreCloseReviewGroup(ctx, in.Reviewer, in.Bead.ID, report.ResultRev, implRouting)
115		reviewRes, reviewGroupErr := reducePreCloseReviewGroup(reviewGroup)
116		chargeReviewCost := func() {
117			if capTracker := in.ReviewCostCap; capTracker != nil && reviewGroup != nil {
118				deferred := false
119				for _, slot := range reviewGroup.Slots {
120					if slot.Result == nil {
121						continue
122					}
123					capTracker.Add(slot.Result.ReviewerHarness, slot.Result.CostUSD)
124					if detail, capped := capTracker.Tripped(); capped && !deferred {
125						_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
126							Kind:      "review-cost-deferred",
127							Summary:   "review-cost-deferred",
128							Body:      ReviewCostDeferredEventBody(report.ResultRev, slot.Result.CostUSD, capTracker.Spent(), capTracker.MaxUSD),
129							Actor:     in.Assignee,
130							Source:    "ddx agent execute-loop",
131							CreatedAt: now().UTC(),
132						})
133						if in.Log != nil {
134							_, _ = fmt.Fprintf(in.Log, "review cost cap deferred (%s %s): %s\n", in.Bead.ID, report.ResultRev, detail)
135						}
136						deferred = true
137					}
138				}
139			}
140		}
141		if reviewGroupErr != nil {
142			reviewErr = reviewGroupErr
143		}
144		if reviewErr != nil {
145			class := ClassifyReviewError(reviewErr, reviewRes)
146			prior := CountPriorReviewErrors(in.Store, in.Bead.ID, report.ResultRev)
147			attemptCount := prior + 1
148			maxRetries := in.Rcfg.ReviewMaxRetries()
149			if maxRetries <= 0 {
150				maxRetries = DefaultReviewMaxRetries
151			}
152			errSummary := EventBodySummary{
153				InputBytes:  0,
154				OutputBytes: 0,
155			}
156			if reviewRes != nil {
157				errSummary = EventBodySummary{
158					Harness:     reviewRes.ReviewerHarness,
159					Model:       reviewRes.ReviewerModel,
160					InputBytes:  reviewRes.InputBytes,
161					OutputBytes: reviewRes.OutputBytes,
162					ElapsedMS:   reviewRes.DurationMS,
163				}
164			}
165			if attemptCount >= maxRetries {
166				body := AppendEventSummary(ReviewErrorEventBody(class, attemptCount, report.ResultRev, reviewErr.Error()), errSummary)
167				_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
168					Kind:      "review-manual-required",
169					Summary:   class,
170					Body:      body,
171					Actor:     in.Assignee,
172					Source:    "ddx agent execute-loop",
173					CreatedAt: now().UTC(),
174				})
175				parkUntil := now().UTC().Add(CapLoopCooldown(MaxLoopCooldown))
176				_ = in.Store.SetExecutionCooldown(in.Bead.ID, parkUntil, "review-manual-required", class)
177			} else {
178				body := AppendEventSummary(ReviewErrorEventBody(class, attemptCount, report.ResultRev, reviewErr.Error()), errSummary)
179				_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
180					Kind:      "review-error",
181					Summary:   class,
182					Body:      body,
183					Actor:     in.Assignee,
184					Source:    "ddx agent execute-loop",
185					CreatedAt: now().UTC(),
186				})
187			}
188			if reviewRes != nil {
189				report.ReviewVerdict = string(reviewRes.Verdict)
190				report.ReviewRationale = reviewRes.Rationale
191			}
192			report.Status = ExecuteBeadStatusReviewMalfunction
193			report.Detail = "pre-close review: " + class
194			out.Report = report
195			out.Approved = false
196			chargeReviewCost()
197			return out
198		}
199	
200		report.ReviewVerdict = string(reviewRes.Verdict)
201		report.ReviewRationale = reviewRes.Rationale
202		artifactPath, artifactErr := PersistReviewerStream(in.ProjectRoot, in.Bead.ID, report.AttemptID, reviewRes.RawOutput)
203		if artifactErr != nil && in.Log != nil {
204			_, _ = fmt.Fprintf(in.Log, "reviewer stream artifact: %v\n", artifactErr)
205		}
206	
207		reviewSummary := EventBodySummary{
208			Harness:     reviewRes.ReviewerHarness,
209			Model:       reviewRes.ReviewerModel,
210			InputBytes:  reviewRes.InputBytes,
211			OutputBytes: reviewRes.OutputBytes,
212			ElapsedMS:   reviewRes.DurationMS,
213		}
214		chargeReviewCost()
215		switch reviewRes.Verdict {
216		case VerdictApprove:
217			// Approved: record the verdict event and then close. The close must
218			// land AFTER the review event so the gate sees the terminal verdict.
219			_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
220				Kind:      "review",
221				Summary:   "APPROVE",
222				Body:      AppendEventSummary(ReviewEventBody("APPROVE", reviewRes.Rationale, artifactPath), reviewSummary),
223				Actor:     in.Assignee,
224				Source:    "ddx agent execute-loop",
225				CreatedAt: now().UTC(),
226			})
227			if cerr := in.Store.CloseWithEvidence(in.Bead.ID, report.SessionID, report.ResultRev); cerr != nil {
228				out.Report = report
229				out.StoreErrOp = "CloseWithEvidence"
230				out.StoreErr = cerr
231				return out
232			}
233		case VerdictRequestChanges:
234			_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
235				Kind:      "review",
236				Summary:   "REQUEST_CHANGES",
237				Body:      AppendEventSummary(ReviewEventBody("REQUEST_CHANGES", reviewRes.Rationale, artifactPath), reviewSummary),
238				Actor:     in.Assignee,
239				Source:    "ddx agent execute-loop",
240				CreatedAt: now().UTC(),
241			})
242			report.Status = ExecuteBeadStatusReviewRequestChanges
243			report.Detail = "pre-close review: REQUEST_CHANGES"
244			out.Approved = false
245		case VerdictBlock:
246			rationale := strings.TrimSpace(reviewRes.Rationale)
247			if rationale == "" {
248				_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
249					Kind:      "review-malfunction",
250					Summary:   "BLOCK without rationale",
251					Body:      AppendEventSummary(ReviewEventBody("BLOCK without rationale", "", artifactPath), reviewSummary),
252					Actor:     in.Assignee,
253					Source:    "ddx agent execute-loop",
254					CreatedAt: now().UTC(),
255				})
256				report.Status = ExecuteBeadStatusReviewMalfunction
257				report.Detail = "pre-close review: malformed BLOCK verdict (missing rationale)"
258				report.ReviewRationale = ""
259				out.Report = report
260				out.Approved = false
261				return out
262			}
263			_ = in.Store.AppendEvent(in.Bead.ID, bead.BeadEvent{
264				Kind:      "review",
265				Summary:   "BLOCK",
266				Body:      AppendEventSummary(rationale, reviewSummary),
267				Actor:     in.Assignee,
268				Source:    "ddx agent execute-loop",
269				CreatedAt: now().UTC(),
270			})
271			report.Status = ExecuteBeadStatusReviewBlock
272			report.Detail = "pre-close review: BLOCK (flagged for human)"
273			out.Approved = false
274		}
275		if reviewRes.Verdict == VerdictBlock || reviewRes.Verdict == VerdictRequestChanges {
276			_ = applyReviewTriageDecision(in.Store, in.Bead.ID, in.Assignee, now().UTC(), report.Tier)
277		}
278	
279		out.Report = report
280		return out
281	}
