283	func runPreCloseReviewGroup(ctx context.Context, reviewer BeadReviewer, beadID, resultRev string, impl ImplementerRouting) (*ReviewGroupResult, error) {
284		if reviewer == nil {
285			return nil, fmt.Errorf("review-group: reviewer required")
286		}
287		if groupReviewer, ok := reviewer.(reviewGroupReviewer); ok {
288			return groupReviewer.ReviewGroup(ctx, beadID, resultRev, impl)
289		}
290		result, err := reviewer.ReviewBead(ctx, beadID, resultRev, impl)
291		group := &ReviewGroupResult{
292			BeadID:    beadID,
293			ResultRev: resultRev,
294			Slots: []ReviewGroupSlotResult{
295				{
296					ReviewerIndex: 0,
297					Result:        result,
298				},
299			},
300		}
301		if err != nil {
302			group.Slots[0].Error = err.Error()
303		}
304		return group, err
305	}
306	
307	func reducePreCloseReviewGroup(group *ReviewGroupResult) (*ReviewResult, error) {
308		if group == nil || len(group.Slots) == 0 {
309			return nil, fmt.Errorf("review-group: no review slots")
310		}
311		var firstApprove *ReviewResult
312		var firstNonApprove *ReviewResult
313		var firstResult *ReviewResult
314		for _, slot := range group.Slots {
315			if slot.Result != nil && firstResult == nil {
316				firstResult = slot.Result
317			}
318			if slot.Error != "" && slot.Result == nil {
319				if firstResult != nil {
320					return firstResult, fmt.Errorf("review-group slot %d: %s", slot.ReviewerIndex, slot.Error)
321				}
322				return nil, fmt.Errorf("review-group slot %d: %s", slot.ReviewerIndex, slot.Error)
323			}
324			if slot.Result == nil {
325				if firstResult != nil {
326					return firstResult, fmt.Errorf("review-group slot %d: missing review result", slot.ReviewerIndex)
327				}
328				return nil, fmt.Errorf("review-group slot %d: missing review result", slot.ReviewerIndex)
329			}
330			res := slot.Result
331			switch res.Verdict {
332			case VerdictApprove:
333				if !reviewResultHasACEvidence(res) {
334					return res, fmt.Errorf("%w: approve verdict without per-AC evidence", ErrReviewVerdictUnparseable)
335				}
336				if firstApprove == nil {
337					firstApprove = res
338				}
339			case VerdictRequestChanges, VerdictBlock:
340				if firstNonApprove == nil {
341					firstNonApprove = res
342				}
343			default:
344				if firstNonApprove == nil {
345					firstNonApprove = res
346				}
347			}
348		}
349		if firstNonApprove != nil {
350			return firstNonApprove, nil
351		}
352		return firstApprove, nil
353	}
354	
355	func reviewResultHasACEvidence(res *ReviewResult) bool {
356		if res == nil || res.Verdict != VerdictApprove {
357			return false
358		}
359		if len(res.PerAC) == 0 {
360			return false
361		}
362		for _, ac := range res.PerAC {
363			if strings.TrimSpace(ac.Evidence) == "" {
364				return false
365			}
366		}
367		return true
368	}
