89	// Node is the resolver for the node(id: ID!) field (Relay lookup by global ID).
90	//
91	// LAYER 3 of the GraphQL multi-project leak fix (ddx-5ae050dc): Bead and
92	// ExecutionRun lookups are scoped to the request's WorkingDir (via
93	// WithWorkingDir/r.workingDir(ctx)) so two projects with overlapping bead IDs
94	// or run IDs do not leak across one another. Unknown ID prefixes return
95	// (nil, nil).
96	func (r *queryResolver) Node(ctx context.Context, id string) (Node, error) {
97		if strings.HasPrefix(id, "node-") {
98			snap := r.State.GetNodeSnapshot()
99			if snap.ID != id {
100				return nil, nil
101			}
102			return nodeInfoFromSnapshot(snap), nil
103		}
104		if strings.HasPrefix(id, "proj-") {
105			proj, ok := r.State.GetProjectSnapshotByID(id)
106			if !ok {
107				return nil, nil
108			}
109			return proj, nil
110		}
111		if strings.HasPrefix(id, "bead-") {
112			beadID := strings.TrimPrefix(id, "bead-")
113			if beadID == "" {
114				return nil, nil
115			}
116			wd := r.workingDir(ctx)
117			if wd == "" {
118				return nil, nil
119			}
120			store := bead.NewStore(filepath.Join(wd, ".ddx"))
121			b, err := store.Get(beadID)
122			if err != nil || b == nil {
123				return nil, nil
124			}
125			snap := BeadSnapshot{
126				ID:          b.ID,
127				Title:       b.Title,
128				Status:      b.Status,
129				Priority:    b.Priority,
130				IssueType:   b.IssueType,
131				Owner:       b.Owner,
132				CreatedAt:   b.CreatedAt,
133				CreatedBy:   b.CreatedBy,
134				UpdatedAt:   b.UpdatedAt,
135				Labels:      b.Labels,
136				Parent:      b.Parent,
137				Description: b.Description,
138				Acceptance:  b.Acceptance,
139				Notes:       b.Notes,
140			}
141			for _, d := range b.Dependencies {
142				snap.Dependencies = append(snap.Dependencies, BeadDependencySnapshot{
143					IssueID:     d.IssueID,
144					DependsOnID: d.DependsOnID,
145					Type:        d.Type,
146					CreatedAt:   d.CreatedAt,
147					CreatedBy:   d.CreatedBy,
148					Metadata:    d.Metadata,
149				})
150			}
151			return beadFromSnapshot(snap), nil
152		}
153		if strings.HasPrefix(id, "exec-") {
154			wd := r.workingDir(ctx)
155			if wd == "" {
156				return nil, nil
157			}
158			store := ddxexec.NewStore(wd)
159			runs, err := store.History("", "")
160			if err != nil {
161				return nil, nil
162			}
163			for _, rec := range runs {
164				if rec.RunID == id {
165					return execRunNodeFromRecord(rec), nil
166				}
167			}
168			return nil, nil
169		}
170		return nil, nil
171	}
