175	// server package but is local to graphql to avoid an import cycle.
176	func execRunNodeFromRecord(rec ddxexec.RunRecord) *ExecutionRun {
177		r := &ExecutionRun{
178			ID:           rec.RunID,
179			DefinitionID: rec.DefinitionID,
180			ArtifactIds:  rec.ArtifactIDs,
181			StartedAt:    rec.StartedAt.UTC().Format(time.RFC3339),
182			FinishedAt:   rec.FinishedAt.UTC().Format(time.RFC3339),
183			Status:       rec.Status,
