203	// Projects is the resolver for the projects field.
204	func (r *queryResolver) Projects(ctx context.Context, first *int, after *string, last *int, before *string, includeUnreachable *bool) (*ProjectConnection, error) {
205		showAll := includeUnreachable != nil && *includeUnreachable
206		projects := r.State.GetProjectSnapshots(showAll)
207	
208		// Build full edge list with stable ID-based cursors.
209		all := make([]*ProjectEdge, len(projects))
210		for i, p := range projects {
211			all[i] = &ProjectEdge{
212				Node:   p,
213				Cursor: encodeStableCursor(p.ID),
214			}
215		}
216	
217		// Apply window: start after `after` cursor, end before `before` cursor.
218		startIdx := 0
219		if after != nil {
220			if afterID, ok := decodeStableCursor(*after); ok {
221				for i, e := range all {
222					if e.Node.ID == afterID {
223						startIdx = i + 1
224						break
225					}
226				}
227			}
228		}
229		endIdx := len(all)
230		if before != nil {
231			if beforeID, ok := decodeStableCursor(*before); ok {
232				for i, e := range all {
233					if e.Node.ID == beforeID {
234						endIdx = i
235						break
236					}
237				}
238			}
239		}
240		if startIdx > endIdx {
241			startIdx = endIdx
242		}
243	
244		slice := all[startIdx:endIdx]
245		if first != nil && *first >= 0 && *first < len(slice) {
246			slice = slice[:*first]
247		}
248		if last != nil && *last >= 0 && *last < len(slice) {
249			slice = slice[len(slice)-*last:]
250		}
251	
252		pageInfo := &PageInfo{
253			HasPreviousPage: startIdx > 0,
254			HasNextPage:     endIdx < len(all),
255		}
256		if len(slice) > 0 {
257			pageInfo.StartCursor = &slice[0].Cursor
258			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
259		}
260	
261		return &ProjectConnection{
262			Edges:      slice,
263			PageInfo:   pageInfo,
264			TotalCount: len(all),
265		}, nil
266	}
