370	// applyReviewTriageDecision runs the triage policy after a BLOCK or
371	// REQUEST_CHANGES review verdict has been recorded for `beadID`. It reads
372	// prior review events to compute the BLOCK count, biases the result toward
373	// re-attempt when the latest BLOCK was paired with a degraded reviewer
374	// (kind:review-pairing-degraded), then applies the chosen action by writing
375	// metadata, labels, and a kind:triage-decision event.
376	//
377	// Errors from the underlying store are best-effort: callers continue
378	// regardless so a triage-side failure cannot strand a bead in an
379	// inconsistent review state. This callout previously lived as a method on
380	// ExecuteBeadWorker; the C3
381	// extraction (ddx-a921ff01) moves it inside the post-merge-review pipeline
382	// driven by RunPostMergeReview / try.Attempt.
383	func applyReviewTriageDecision(store ExecuteBeadLoopStore, beadID, actor string, now time.Time, currentTier string) error {
384		events, err := store.Events(beadID)
385		if err != nil {
386			return err
387		}
388	
389		var blockTimestamps []time.Time
390		var pairingDegraded []time.Time
391		for _, ev := range events {
392			switch {
393			case ev.Kind == "review" && strings.TrimSpace(ev.Summary) == "BLOCK":
394				blockTimestamps = append(blockTimestamps, ev.CreatedAt)
395			case ev.Kind == ReviewPairingDegradedEventKind:
396				pairingDegraded = append(pairingDegraded, ev.CreatedAt)
397			}
398		}
399	
400		// History excludes the current attempt. The just-appended BLOCK (if any)
401		// is the last entry in blockTimestamps and must not be counted as prior
402		// history per triage.Decide()'s contract.
403		historyCount := len(blockTimestamps)
404		if historyCount > 0 {
405			historyCount--
406		}
407		history := make([]triage.FailureMode, 0, historyCount)
408		for i := 0; i < historyCount; i++ {
409			history = append(history, triage.FailureModeReviewBlock)
410		}
411	
412		policy := triage.DefaultPolicy()
413		action := policy.Decide(beadID, triage.FailureModeReviewBlock, history)
414	
415		pairedDegraded := latestBlockPairedDegraded(blockTimestamps, pairingDegraded)
416		if pairedDegraded && action == triage.ActionEscalateTier {
417			action = triage.ActionReAttemptWithContext
418		}
419	
420		return applyTriageAction(store, beadID, actor, now, action, currentTier, pairedDegraded)
421	}
422	
423	// latestBlockPairedDegraded reports whether the most recent BLOCK event was
424	// paired with a review-pairing-degraded event from the same attempt window
425	// (between the previous BLOCK and this one).
426	func latestBlockPairedDegraded(blocks, pairing []time.Time) bool {
427		if len(blocks) == 0 || len(pairing) == 0 {
428			return false
429		}
430		latest := blocks[len(blocks)-1]
431		var prev time.Time
432		if len(blocks) >= 2 {
433			prev = blocks[len(blocks)-2]
434		}
435		for _, t := range pairing {
436			if t.After(prev) && !t.After(latest) {
437				return true
438			}
439		}
440		return false
441	}
442	
443	// applyTriageAction performs the side effects for a chosen Action: writes a
444	// tier-pin hint into bead.Extra (escalate_tier), appends a needs_human label
445	// (needs_human), and always records a kind:triage-decision event.
446	func applyTriageAction(store ExecuteBeadLoopStore, beadID, actor string, now time.Time, action triage.Action, currentTier string, pairedDegraded bool) error {
447		body := map[string]any{
448			"action": string(action),
449			"mode":   string(triage.FailureModeReviewBlock),
450		}
451		if pairedDegraded {
452			body["pairing_degraded"] = true
453		}
454	
455		switch action {
456		case triage.ActionEscalateTier:
457			nextTier := nextEscalatedTier(currentTier)
458			body["tier_hint"] = string(nextTier)
459			_ = store.Update(beadID, func(b *bead.Bead) {
460				if b.Extra == nil {
461					b.Extra = make(map[string]any)
462				}
463				b.Extra[TriageTierHintKey] = string(nextTier)
464			})
465		case triage.ActionNeedsHuman:
466			_ = store.Update(beadID, func(b *bead.Bead) {
467				if !HasBeadLabel(b.Labels, TriageNeedsHumanLabel) {
468					b.Labels = append(b.Labels, TriageNeedsHumanLabel)
469				}
470			})
471		}
472	
473		bodyJSON, _ := json.Marshal(body)
474		return store.AppendEvent(beadID, bead.BeadEvent{
475			Kind:      triageDecisionEventKind,
476			Summary:   string(triage.FailureModeReviewBlock) + ": " + string(action),
477			Body:      string(bodyJSON),
478			Actor:     actor,
479			Source:    "ddx agent execute-loop",
480			CreatedAt: now,
481		})
482	}
483	
484	// nextEscalatedTier returns the next tier above `current`. An unrecognised or
485	// empty current tier defaults to standard; smart is its own ceiling.
486	func nextEscalatedTier(current string) escalation.ModelTier {
487		switch escalation.ModelTier(current) {
488		case escalation.TierCheap:
489			return escalation.TierStandard
490		case escalation.TierStandard:
491			return escalation.TierSmart
492		case escalation.TierSmart:
493			return escalation.TierSmart
494		default:
495			return escalation.TierStandard
496		}
497	}
