1	// Package bead implements the on-disk bead tracker.
2	//
3	// Size envelope (ddx-f8a11202):
4	//
5	// Individual bead fields — description, acceptance, notes, and each event's
6	// body — are bounded by MaxFieldBytes (65,535 bytes). This matches upstream
7	// bd's Dolt TEXT column limit so DDx-authored beads can always round-trip
8	// through `bd import`. Writers exceeding the cap are truncated with a
9	// `…[truncated, N bytes]` marker at AppendEvent; callers that need to
10	// preserve the full payload (notably reviewer streams) should persist to a
11	// sidecar artifact under `.ddx/executions/<id>/` and record a path
12	// reference in the event body.
13	//
14	// On the read side, scanners use a 16MB buffer — real-world incidents have
15	// produced 1.46MB bead rows and ~7MB session-log rows when writers bypassed
16	// the cap. 16MB comfortably fits a bead with dozens of maxed-out fields and
17	// matches the scanner in the agent package.
18	package bead
19	
20	import (
21		"bufio"
22		"bytes"
23		"context"
24		"crypto/rand"
25		"encoding/hex"
26		"encoding/json"
27		"fmt"
28		"os"
29		"path/filepath"
30		"sort"
31		"strconv"
32		"strings"
33		"time"
34	
35		"github.com/DocumentDrivenDX/ddx/internal/config"
36		gitpkg "github.com/DocumentDrivenDX/ddx/internal/git"
37	)
38	
39	// Store manages beads via a pluggable backend.
40	type Store struct {
41		Collection string
42		Dir        string
43		File       string
44		Prefix     string
45		LockDir    string
46		LockWait   time.Duration
47		backend    RawBackend // nil means use built-in JSONL
48	}
49	
50	// Compile-time check: *Store satisfies the high-level Backend interface
51	// declared in backend.go. This is the contract chaos_test.go and (eventually)
52	// cli/cmd callers program against.
53	var _ Backend = (*Store)(nil)
54	
55	type StoreOption func(*Store)
56	
57	// WithCollection selects the logical bead collection. The default collection
58	// remains "beads", which maps to "beads.jsonl" in the JSONL backend.
59	func WithCollection(name string) StoreOption {
60		return func(s *Store) {
61			if cleaned := normalizeCollection(name); cleaned != "" {
62				s.Collection = cleaned
63			}
64		}
65	}
66	
67	// NewStore creates a store with the given directory.
68	// Defaults can be overridden via options or environment.
69	func NewStore(dir string, opts ...StoreOption) *Store {
70		if dir == "" {
71			dir = envOr("DDX_BEAD_DIR", ".ddx")
72		}
73		workingDir := dir
74		if filepath.Base(dir) == ".ddx" {
75			workingDir = filepath.Dir(dir)
76		}
77		prefix := envOr("DDX_BEAD_PREFIX", "")
78		var configBackend string
79		if cfg, err := config.LoadWithWorkingDir(workingDir); err == nil && cfg != nil && cfg.Bead != nil {
80			if prefix == "" && cfg.Bead.IDPrefix != "" {
81				prefix = cfg.Bead.IDPrefix
82			}
83			configBackend = cfg.Bead.Backend
84		}
85		if prefix == "" {
86			prefix = detectPrefix(workingDir)
87		}
88		// Backend selection: env var wins, then config, then jsonl default.
89		backendType := os.Getenv("DDX_BEAD_BACKEND")
90		if backendType == "" {
91			backendType = configBackend
92		}
93		if backendType == "" {
94			backendType = BackendJSONL
95		}
96	
97		s := &Store{
98			Collection: DefaultCollection,
99			Dir:        dir,
100			Prefix:     prefix,
101			LockWait:   parseDurationOr("DDX_BEAD_LOCK_TIMEOUT", 10*time.Second),
102		}
103		for _, opt := range opts {
104			if opt != nil {
105				opt(s)
106			}
107		}
108		spec := DefaultRegistry().Resolve(CollectionID(s.Collection))
109		s.File, s.LockDir = spec.PathsUnder(dir)
110	
111		// Set up external backend if configured. bd/br lack per-collection
112		// scoping in their CLI, so non-default collections (e.g. beads-archive)
113		// route through a JSONL fallback the external backend transparently
114		// delegates to. The default collection always goes straight to bd/br
115		// to preserve the existing interchange contract (schema_compat_test.go,
116		// import/export round-trip).
117		switch backendType {
118		case BackendBD, BackendBR:
119			var fallback RawBackend
120			if s.Collection != DefaultCollection {
121				fallback = NewJSONLBackend(s.Dir, s.File, s.LockDir, s.LockWait)
122			}
123			if ext, err := NewExternalBackendWithFallback(backendType, s.Collection, fallback); err == nil {
124				s.backend = ext
125			}
126			// Fall through to JSONL if tool not available
127		case BackendAxon:
128			s.backend = NewAxonBackend(s.Dir, s.LockWait)
129		}
130	
131		return s
132	}
133	
134	// NewStoreWithCollection creates a store for a named logical collection.
135	func NewStoreWithCollection(dir, collection string) *Store {
136		return NewStore(dir, WithCollection(collection))
137	}
138	
139	// Init creates the storage directory and file.
140	func (s *Store) Init() error {
141		if s.backend != nil {
142			return s.backend.Init()
143		}
144		if err := os.MkdirAll(s.Dir, 0o755); err != nil {
145			return fmt.Errorf("bead: init dir: %w", err)
146		}
147		f, err := os.OpenFile(s.File, os.O_CREATE|os.O_WRONLY, 0o644)
148		if err != nil {
149			return fmt.Errorf("bead: init file: %w", err)
150		}
151		return f.Close()
152	}
153	
154	// GenID generates a unique bead ID with the configured prefix.
155	func (s *Store) GenID() (string, error) {
156		b := make([]byte, 4)
157		if _, err := rand.Read(b); err != nil {
158			return "", fmt.Errorf("bead: gen id: %w", err)
159		}
160		return fmt.Sprintf("%s-%s", s.Prefix, hex.EncodeToString(b)), nil
161	}
162	
163	// ReadAll loads all beads from the configured backend.
164	func (s *Store) ReadAll() ([]Bead, error) {
165		return s.ReadAllFiltered(nil)
166	}
167	
168	// ReadAllFiltered loads all beads, folds them by latest-wins, and returns only
169	// those for which the predicate returns true. When the predicate is nil every
170	// bead is returned (equivalent to ReadAll). The predicate is applied at the
171	// per-entry parse boundary after fold — matched beads are appended directly to
172	// the return slice without first being held in an intermediate full-corpus
173	// list, so queries that match a small subset avoid materializing the
174	// mismatches (ddx-9ce6842a Part 2 step 2: filter pushdown).
175	func (s *Store) ReadAllFiltered(pred func(Bead) bool) ([]Bead, error) {
176		if s.backend != nil {
177			all, err := s.backend.ReadAll()
178			if err != nil {
179				return nil, err
180			}
181			if pred == nil {
182				return all, nil
183			}
184			out := make([]Bead, 0, len(all))
185			for _, b := range all {
186				if pred(b) {
187					out = append(out, b)
188				}
189			}
190			return out, nil
191		}
192		beads, warnings, err := s.readAllRaw()
193		if err != nil {
194			return nil, fmt.Errorf("bead: read %s: %w", s.File, err)
195		}
196		beads = foldLatestBeads(beads)
197		for _, warning := range warnings {
198			fmt.Fprintln(os.Stderr, warning)
199		}
200		if len(warnings) > 0 && len(beads) > 0 {
201			repaired, repairErr := s.repairJSONL()
202			if repairErr != nil {
203				return beads, fmt.Errorf("bead: repair %s: %w", s.File, repairErr)
204			}
205			if repaired {
206				fmt.Fprintf(os.Stderr, "bead: repaired %s; backup written to %s.bak\n", s.File, s.File)
207			}
208		}
209		if len(beads) == 0 && len(warnings) > 0 {
210			return nil, fmt.Errorf("bead: read %s: %d malformed record(s), 0 valid", s.File, len(warnings))
211		}
212		if pred == nil {
213			return beads, nil
214		}
215		out := make([]Bead, 0, len(beads))
216		for _, b := range beads {
217			if pred(b) {
218				out = append(out, b)
219			}
220		}
221		return out, nil
222	}
223	
224	func (s *Store) readAllRaw() ([]Bead, []string, error) {
225		data, err := os.ReadFile(s.File)
226		if os.IsNotExist(err) {
227			return nil, nil, nil
228		}
229		if err != nil {
230			return nil, nil, fmt.Errorf("read: %w", err)
231		}
232		beads, warnings, err := parseBeadJSONL(data)
233		if err != nil {
234			return nil, nil, err
235		}
236		return beads, warnings, nil
237	}
238	
239	func parseBeadJSONL(data []byte) ([]Bead, []string, error) {
240		scanner := bufio.NewScanner(bytes.NewReader(data))
241		// 16MB max line. Real-world extremes observed: 1.46MB bead rows when a
242		// reviewer stream dumped into events[].body, and bd-exported lines stacking
243		// many 65KB fields. bd's upstream per-field cap is 65,535 bytes; an
244		// individual bead with dozens of maxed-out fields fits comfortably in 16MB.
245		scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
246	
247		var beads []Bead
248		var warnings []string
249		lineNo := 0
250		for scanner.Scan() {
251			lineNo++
252			line := strings.TrimSpace(scanner.Text())
253			if line == "" {
254				continue
255			}
256			b, err := unmarshalBead([]byte(line))
257			if err != nil {
258				warnings = append(warnings, fmt.Sprintf("bead: read line %d: %v", lineNo, err))
259				continue
260			}
261			beads = append(beads, b)
262		}
263		if err := scanner.Err(); err != nil {
264			return nil, nil, fmt.Errorf("scan jsonl: %w", err)
265		}
266		return beads, warnings, nil
267	}
268	
269	func (s *Store) repairJSONL() (bool, error) {
270		var repaired bool
271		err := s.WithLock(func() error {
272			beads, warnings, err := s.readAllRaw()
273			if err != nil {
274				return err
275			}
276			beads = foldLatestBeads(beads)
277			if len(warnings) == 0 || len(beads) == 0 {
278				return nil
279			}
280			backupPath := s.File + ".bak"
281			backupData, err := os.ReadFile(s.File)
282			if err != nil {
283				return fmt.Errorf("read current file: %w", err)
284			}
285			if err := writeAtomicFile(backupPath, backupData); err != nil {
286				return fmt.Errorf("write backup: %w", err)
287			}
288			if err := s.WriteAll(beads); err != nil {
289				return fmt.Errorf("write repaired file: %w", err)
290			}
291			repaired = true
292			return nil
293		})
294		return repaired, err
295	}
296	
297	func foldLatestBeads(beads []Bead) []Bead {
298		if len(beads) == 0 {
299			return nil
300		}
301	
302		latest := make(map[string]Bead, len(beads))
303		lastSeen := make(map[string]int, len(beads))
304		for i, b := range beads {
305			latest[b.ID] = b
306			lastSeen[b.ID] = i
307		}
308	
309		ids := make([]string, 0, len(latest))
310		for id := range latest {
311			ids = append(ids, id)
312		}
313		sort.Slice(ids, func(i, j int) bool {
314			if lastSeen[ids[i]] != lastSeen[ids[j]] {
315				return lastSeen[ids[i]] < lastSeen[ids[j]]
316			}
317			return ids[i] < ids[j]
318		})
319	
320		out := make([]Bead, 0, len(ids))
321		for _, id := range ids {
322			out = append(out, latest[id])
323		}
324		return out
325	}
326	
327	func (s *Store) readAllLatestRaw() ([]Bead, []string, error) {
328		// When a non-JSONL backend is configured, the raw bead corpus lives
329		// outside .ddx/<collection>.jsonl entirely (axon: two collections under
330		// .ddx/axon/; bd/br: an external tool's store). Delegate the read so
331		// every read-modify-write path inside Store stays consistent with the
332		// backend's storage layout. Backends are responsible for returning
333		// already-folded beads.
334		if s.backend != nil {
335			all, err := s.backend.ReadAll()
336			if err != nil {
337				return nil, nil, err
338			}
339			return all, nil, nil
340		}
341		beads, warnings, err := s.readAllRaw()
342		if err != nil {
343			return nil, nil, err
344		}
345		return foldLatestBeads(beads), warnings, nil
346	}
