348	// tmpPath returns a unique temp file path in the same directory as path.
349	// Uses pid + 4 random bytes so concurrent processes don't collide.
350	func tmpPath(path string) (string, error) {
351		b := make([]byte, 4)
352		if _, err := rand.Read(b); err != nil {
353			return "", err
354		}
355		return fmt.Sprintf("%s.tmp-%d-%s", path, os.Getpid(), hex.EncodeToString(b)), nil
356	}
357	
358	func writeAtomicFile(path string, data []byte) error {
359		tmp, err := tmpPath(path)
360		if err != nil {
361			return err
362		}
363		f, err := os.OpenFile(tmp, os.O_WRONLY|os.O_CREATE|os.O_EXCL, 0o644)
364		if err != nil {
365			return err
366		}
367		if _, err := f.Write(data); err != nil {
368			f.Close()
369			_ = os.Remove(tmp)
370			return err
371		}
372		if err := f.Sync(); err != nil {
373			f.Close()
374			_ = os.Remove(tmp)
375			return err
376		}
377		if err := f.Close(); err != nil {
378			_ = os.Remove(tmp)
379			return err
380		}
381		if err := os.Rename(tmp, path); err != nil {
382			_ = os.Remove(tmp)
383			return err
384		}
385		return nil
386	}
