734			if b.Status == StatusInProgress {
735				b.Status = StatusOpen
736			}
737			b.Owner = ""
738			if b.Extra != nil {
739				delete(b.Extra, "claimed-at")
740				delete(b.Extra, "claimed-pid")
741				delete(b.Extra, "claimed-machine")
742				delete(b.Extra, "claimed-session")
743				delete(b.Extra, "claimed-worktree")
744				delete(b.Extra, "execute-loop-heartbeat-at")
745			}
746		}); err != nil {
747			return err
748		}
749		return s.RemoveClaimHeartbeat(id)
750	}
