886	func (s *Store) AppendEvent(id string, event BeadEvent) error {
887		if event.CreatedAt.IsZero() {
888			event.CreatedAt = time.Now().UTC()
889		}
890		// Defense in depth: cap every event body regardless of caller. The
891		// reviewer write path separately persists the full stream to an artifact
892		// and emits a <=512-byte body; this cap catches anything else.
893		event.Body = capFieldBytes(event.Body)
894		event.Summary = capFieldBytes(event.Summary)
895		// Two storage shapes are possible here: inline Extra["events"] for active
896		// beads, and a sidecar attachment for closed/archived beads (ADR-004
897		// attachment model). When the bead has been externalized we append to the
898		// sidecar and leave the row untouched aside from updated_at.
899		var appendedToAttachment bool
900		if err := s.Update(id, func(b *Bead) {
901			if b.Extra == nil {
902				b.Extra = make(map[string]any)
903			}
904			if hasEventsAttachment(b) {
905				appendedToAttachment = true
906				return
907			}
908			var events []BeadEvent
909			if raw, ok := b.Extra["events"]; ok {
910				events = decodeBeadEvents(raw)
911			}
912			events = append(events, event)
913			b.Extra["events"] = encodeEventsForExtra(events)
914		}); err != nil {
915			return err
916		}
917		if !appendedToAttachment {
918			return nil
919		}
920		// Append to the sidecar under the store lock so concurrent readers and
921		// writers see a consistent events log.
922		return s.WithLock(func() error {
923			existing, err := s.readEventsAttachment(id)
924			if err != nil {
925				return err
926			}
927			existing = append(existing, event)
928			return s.writeEventsAttachment(id, existing)
929		})
930	}
