1167	func appendClosureRejectNote(b *Bead, err error) {
1168		stamp := time.Now().UTC().Format(time.RFC3339)
1169		note := fmt.Sprintf("[%s] closure rejected: %v", stamp, err)
1170		if b.Notes == "" {
1171			b.Notes = note
1172			return
1173		}
1174		b.Notes = b.Notes + "\n" + note
1175	}
