1358	// ReadyExecutionBreakdown classifies dependency-ready beads by the reason
1359	// they are NOT execution-eligible: lifecycle-blocked statuses, epic
1360	// containers, retry cooldown, execution-eligible=false, or superseded. It's
1361	// the diagnostic the work loop emits when the execution queue is empty but
1362	// `ddx bead ready` is not.
1363	type ReadyExecutionBreakdown struct {
1364		SkippedEpics                 []string
1365		SkippedEpicClosureCandidates []string
1366		SkippedOnCooldown            []string
1367		SkippedNeedsInvestigation    []string
1368		SkippedBlocked               []string
1369		SkippedNotEligible           []string
1370		SkippedSuperseded            []string
1371		NextRetryAfter               string
1372	}
1373	
1374	func (s *Store) ReadyExecutionBreakdown() (ReadyExecutionBreakdown, error) {
1375		out := ReadyExecutionBreakdown{}
1376		beads, err := s.ReadAll()
1377		if err != nil {
1378			return out, err
1379		}
1380		statusMap := make(map[string]string)
1381		childCount := make(map[string]int)
1382		openChildCount := make(map[string]int)
1383		for _, b := range beads {
1384			statusMap[b.ID] = b.Status
1385			if b.Parent != "" {
1386				childCount[b.Parent]++
1387				if b.Status != StatusClosed {
1388					openChildCount[b.Parent]++
1389				}
1390			}
1391		}
1392		now := time.Now().UTC()
1393		var soonestRetry time.Time
1394		for _, b := range beads {
1395			if !depsSatisfied(b, statusMap) {
1396				continue
1397			}
1398			switch b.Status {
1399			case StatusBlocked, StatusProposed, StatusCancelled:
1400				out.SkippedBlocked = append(out.SkippedBlocked, b.ID)
1401				continue
1402			case StatusInProgress:
1403				if !claimLeaseIsStale(s, b.Extra, b.ID) {
1404					continue
1405				}
1406			case StatusOpen:
1407			default:
1408				continue
1409			}
1410			if retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]; ok {
1411				if retryAfterStr, isStr := retryAfterRaw.(string); isStr && retryAfterStr != "" {
1412					if retryAfter, err := time.Parse(time.RFC3339, retryAfterStr); err == nil && retryAfter.After(now) {
1413						out.SkippedOnCooldown = append(out.SkippedOnCooldown, b.ID)
1414						if soonestRetry.IsZero() || retryAfter.Before(soonestRetry) {
1415							soonestRetry = retryAfter
1416						}
1417						continue
1418					}
1419				}
1420			}
1421			if isOrdinaryEpicContainer(b, childCount[b.ID]) {
1422				if isEpicClosureCandidate(b, childCount[b.ID], openChildCount[b.ID]) {
1423					out.SkippedEpicClosureCandidates = append(out.SkippedEpicClosureCandidates, b.ID)
1424				} else {
1425					out.SkippedEpics = append(out.SkippedEpics, b.ID)
1426				}
1427				continue
1428			}
1429			if hasLabel(b, LabelNeedsInvestigation) || hasLabel(b, LabelNeedsHuman) || hasNoChangesTriageLabel(b) {
1430				out.SkippedNeedsInvestigation = append(out.SkippedNeedsInvestigation, b.ID)
1431				continue
1432			}
1433			if eligible, ok := b.Extra["execution-eligible"]; ok {
1434				if val, isBool := eligible.(bool); isBool && !val {
1435					out.SkippedNotEligible = append(out.SkippedNotEligible, b.ID)
1436					continue
1437				}
1438			}
1439			if sup, ok := b.Extra["superseded-by"]; ok {
1440				if s, isStr := sup.(string); isStr && s != "" {
1441					out.SkippedSuperseded = append(out.SkippedSuperseded, b.ID)
1442					continue
1443				}
1444			}
1445		}
1446		if !soonestRetry.IsZero() {
1447			out.NextRetryAfter = soonestRetry.Format(time.RFC3339)
1448		}
1449		return out, nil
1450	}
1451	
1452	func (s *Store) readyFiltered(executionOnly bool) ([]Bead, error) {
1453		beads, err := s.ReadAll()
1454		if err != nil {
1455			return nil, err
1456		}
1457		statusMap := make(map[string]string)
1458		childCount := make(map[string]int)
1459		for _, b := range beads {
1460			statusMap[b.ID] = b.Status
1461			if b.Parent != "" {
1462				childCount[b.Parent]++
1463			}
1464		}
1465	
1466		var ready []Bead
1467		for _, b := range beads {
1468			if b.Status != StatusOpen {
1469				// Surface stalled in_progress beads so a fresh worker can
1470				// reclaim them atomically in Claim().
1471				if executionOnly && b.Status == StatusInProgress && claimLeaseIsStale(s, b.Extra, b.ID) {
1472					// fall through to dependency check below
1473				} else {
1474					continue
1475				}
1476			}
1477			allSatisfied := true
1478			for _, depID := range b.DepIDs() {
1479				if statusMap[depID] != StatusClosed {
1480					allSatisfied = false
1481					break
1482				}
1483			}
1484			if !allSatisfied {
1485				continue
1486			}
1487			if executionOnly {
1488				if hasLabel(b, LabelNeedsInvestigation) || hasLabel(b, LabelNeedsHuman) || hasNoChangesTriageLabel(b) {
1489					continue
1490				}
1491				if isOrdinaryEpicContainer(b, childCount[b.ID]) {
1492					continue
1493				}
1494				// Filter by execution-eligible (default true if absent)
1495				eligible, ok := b.Extra["execution-eligible"]
1496				if ok {
1497					if val, isBool := eligible.(bool); isBool && !val {
1498						continue
1499					}
1500				}
1501				// Filter out superseded beads
1502				if sup, ok := b.Extra["superseded-by"]; ok {
1503					if s, isStr := sup.(string); isStr && s != "" {
1504						continue
1505					}
1506				}
1507				if retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]; ok {
1508					if retryAfterStr, isStr := retryAfterRaw.(string); isStr && retryAfterStr != "" {
1509						if retryAfter, err := time.Parse(time.RFC3339, retryAfterStr); err == nil && retryAfter.After(time.Now().UTC()) {
1510							continue
1511						}
1512					}
1513				}
1514			}
1515			ready = append(ready, b)
1516		}
1517	
1518		sortBeadsForQueue(ready)
1519	
1520		return ready, nil
1521	}
1522	
1523	func hasNoChangesTriageLabel(b Bead) bool {
1524		return hasLabel(b, LabelNoChangesUnjustified) || hasLabel(b, LabelNoChangesUnverified)
1525	}
