1527	// Blocked returns open beads with at least one unclosed dependency.
1528	func (s *Store) Blocked() ([]Bead, error) {
1529		beads, err := s.ReadAll()
1530		if err != nil {
1531			return nil, err
1532		}
1533		statusMap := make(map[string]string)
1534		for _, b := range beads {
1535			statusMap[b.ID] = b.Status
1536		}
1537	
1538		var blocked []Bead
1539		for _, b := range beads {
1540			if b.Status != StatusOpen {
1541				continue
1542			}
1543			for _, depID := range b.DepIDs() {
1544				if statusMap[depID] != StatusClosed {
1545					blocked = append(blocked, b)
1546					break
1547				}
1548			}
1549		}
1550		sortBeadsForQueue(blocked)
1551		return blocked, nil
1552	}
1553	
1554	// BlockedAll returns open beads that are currently not runnable, classified
1555	// by blocker kind. Dependency-blocked beads are emitted first (any unclosed
1556	// dep in their DAG); retry-parked beads whose execute-loop-retry-after is in
1557	// the future are emitted with blocker kind BlockerKindRetryCooldown. A bead
1558	// that is both dep-blocked and cooldown-parked is reported as dependency-
1559	// blocked, because deps are the stronger blocker.
1560	func (s *Store) BlockedAll() ([]BlockedBead, error) {
1561		beads, err := s.ReadAll()
1562		if err != nil {
1563			return nil, err
1564		}
1565		statusMap := make(map[string]string)
1566		childCount := make(map[string]int)
1567		for _, b := range beads {
1568			statusMap[b.ID] = b.Status
1569			if b.Parent != "" {
1570				childCount[b.Parent]++
1571			}
1572		}
1573	
1574		now := time.Now().UTC()
1575		var entries []BlockedBead
1576		for _, b := range beads {
1577			if b.Status != StatusOpen && b.Status != StatusBlocked {
1578				continue
1579			}
1580	
1581			var unclosed []string
1582			for _, depID := range b.DepIDs() {
1583				if statusMap[depID] != StatusClosed {
1584					unclosed = append(unclosed, depID)
1585				}
1586			}
1587			if len(unclosed) > 0 {
1588				entries = append(entries, BlockedBead{
1589					Bead: b,
1590					Blocker: Blocker{
1591						Kind:           BlockerKindDependency,
1592						UnclosedDepIDs: unclosed,
1593					},
1594				})
1595				continue
1596			}
1597			if b.Status == StatusBlocked {
1598				entries = append(entries, BlockedBead{
1599					Bead: b,
1600					Blocker: Blocker{
1601						Kind:   BlockerKindBlockedStatus,
1602						Reason: "persisted blocked status",
1603					},
1604				})
1605				continue
1606			}
1607	
1608			if hasLabel(b, LabelNeedsInvestigation) || hasLabel(b, LabelNeedsHuman) {
1609				entries = append(entries, BlockedBead{
1610					Bead: b,
1611					Blocker: Blocker{
1612						Kind:       BlockerKindNeedsInvestigation,
1613						LastStatus: "no_changes",
1614						Reason:     "triage needs investigation before retry",
1615					},
1616				})
1617				continue
1618			}
1619			if isOrdinaryEpicContainer(b, childCount[b.ID]) {
1620				entries = append(entries, BlockedBead{
1621					Bead: b,
1622					Blocker: Blocker{
1623						Kind:   BlockerKindEpicOnly,
1624						Reason: "ordinary ddx work skips epic/container beads",
1625					},
1626				})
1627				continue
1628			}
1629	
1630			if eligible, ok := b.Extra["execution-eligible"]; ok {
1631				if val, isBool := eligible.(bool); isBool && !val {
1632					reason, _ := b.Extra["execution-skip-reason"].(string)
1633					entries = append(entries, BlockedBead{
1634						Bead: b,
1635						Blocker: Blocker{
1636							Kind:   BlockerKindNotEligible,
1637							Reason: reason,
1638						},
1639					})
1640					continue
1641				}
1642			}
1643			if sup, ok := b.Extra["superseded-by"]; ok {
1644				if s, isStr := sup.(string); isStr && s != "" {
1645					entries = append(entries, BlockedBead{
1646						Bead: b,
1647						Blocker: Blocker{
1648							Kind:   BlockerKindSuperseded,
1649							Reason: s,
1650						},
1651					})
1652					continue
1653				}
1654			}
1655	
1656			retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]
1657			if !ok {
1658				continue
1659			}
1660			retryAfterStr, isStr := retryAfterRaw.(string)
1661			if !isStr || retryAfterStr == "" {
1662				continue
1663			}
1664			retryAfter, err := time.Parse(time.RFC3339, retryAfterStr)
1665			if err != nil || !retryAfter.After(now) {
1666				continue
1667			}
1668			blocker := Blocker{
1669				Kind:           BlockerKindRetryCooldown,
1670				NextEligibleAt: retryAfter.UTC().Format(time.RFC3339),
1671			}
1672			if v, ok := b.Extra["execute-loop-last-status"]; ok {
1673				if s, ok := v.(string); ok {
1674					blocker.LastStatus = s
1675				}
1676			}
1677			if v, ok := b.Extra["execute-loop-last-detail"]; ok {
1678				if s, ok := v.(string); ok {
1679					blocker.LastDetail = s
1680				}
1681			}
1682			entries = append(entries, BlockedBead{
1683				Bead:    b,
1684				Blocker: blocker,
1685			})
1686		}
1687	
1688		sort.SliceStable(entries, func(i, j int) bool {
1689			if entries[i].Priority != entries[j].Priority {
1690				return entries[i].Priority < entries[j].Priority
1691			}
1692			if !entries[i].CreatedAt.Equal(entries[j].CreatedAt) {
1693				return entries[i].CreatedAt.Before(entries[j].CreatedAt)
1694			}
1695			return entries[i].ID < entries[j].ID
1696		})
1697		return entries, nil
1698	}
1699	
1700	func depsSatisfied(b Bead, statusMap map[string]string) bool {
1701		for _, depID := range b.DepIDs() {
1702			if statusMap[depID] != StatusClosed {
1703				return false
1704			}
1705		}
1706		return true
1707	}
