1709	func isOrdinaryEpicContainer(b Bead, childCount int) bool {
1710		issueType := strings.ToLower(strings.TrimSpace(b.IssueType))
1711		title := strings.ToLower(strings.TrimSpace(b.Title))
1712		return issueType == "epic" || strings.HasPrefix(title, "epic:") || (childCount > 0 && strings.HasPrefix(title, "epic "))
1713	}
1714	
1715	func isEpicClosureCandidate(b Bead, childCount, openChildCount int) bool {
1716		if childCount == 0 {
1717			return false
1718		}
1719		return isOrdinaryEpicContainer(b, childCount) && openChildCount == 0
1720	}
1721	
1722	func sortBeadsForQueue(beads []Bead) {
1723		sort.SliceStable(beads, func(i, j int) bool {
1724			if beads[i].Priority != beads[j].Priority {
1725				return beads[i].Priority < beads[j].Priority
1726			}
1727			ir, iok := parseQueueRank(beads[i].Extra["queue-rank"])
1728			jr, jok := parseQueueRank(beads[j].Extra["queue-rank"])
1729			if iok != jok {
1730				return iok
1731			}
1732			if iok && jok && ir != jr {
1733				return ir < jr
1734			}
1735			if !beads[i].CreatedAt.Equal(beads[j].CreatedAt) {
1736				return beads[i].CreatedAt.Before(beads[j].CreatedAt)
1737			}
1738			return beads[i].ID < beads[j].ID
1739		})
1740	}
1741	
1742	func parseQueueRank(raw any) (int, bool) {
1743		switch v := raw.(type) {
1744		case int:
1745			return v, true
1746		case int8:
1747			return int(v), true
1748		case int16:
1749			return int(v), true
1750		case int32:
1751			return int(v), true
1752		case int64:
1753			return int(v), true
1754		case uint:
1755			return int(v), true
1756		case uint8:
1757			return int(v), true
1758		case uint16:
1759			return int(v), true
1760		case uint32:
1761			return int(v), true
1762		case uint64:
1763			return int(v), true
1764		case float32:
1765			return int(v), v == float32(int(v))
1766		case float64:
1767			return int(v), v == float64(int(v))
1768		case json.Number:
1769			if n, err := v.Int64(); err == nil {
1770				return int(n), true
1771			}
1772			if f, err := v.Float64(); err == nil {
1773				return int(f), f == float64(int(f))
1774			}
1775		case string:
1776			if n, err := strconv.Atoi(strings.TrimSpace(v)); err == nil {
1777				return n, true
1778			}
1779		}
1780		return 0, false
1781	}
