1887	// DepTree returns a text representation of the dependency tree.
1888	func (s *Store) DepTree(rootID string) (string, error) {
1889		beads, err := s.ReadAll()
1890		if err != nil {
1891			return "", err
1892		}
1893		// Pull in archive partner so the tree survives `bead migrate` — closed
1894		// beads stored only in the archive must still appear.
1895		if s.Collection == DefaultCollection {
1896			archive := s.archivePartner()
1897			if archived, aerr := archive.ReadAll(); aerr == nil {
1898				seen := make(map[string]bool, len(beads))
1899				for _, b := range beads {
1900					seen[b.ID] = true
1901				}
1902				for _, b := range archived {
1903					if seen[b.ID] {
1904						continue
1905					}
1906					beads = append(beads, b)
1907				}
1908			}
1909		}
1910		byID := make(map[string]*Bead)
1911		for i := range beads {
1912			byID[beads[i].ID] = &beads[i]
1913		}
1914	
1915		if rootID != "" {
1916			target, ok := byID[rootID]
1917			if !ok {
1918				return "", fmt.Errorf("bead: not found: %s", rootID)
1919			}
1920			var sb strings.Builder
1921			// Walk up: show the dependency chain (what this node depends on)
1922			depChain := s.depChainUp(byID, rootID)
1923			if len(depChain) > 0 {
1924				// Print deps as the tree root(s), with the target as their child
1925				for _, depID := range depChain {
1926					if dep, ok := byID[depID]; ok {
1927						fmt.Fprintf(&sb, "%s [%s] %s\n", dep.ID, dep.Status, dep.Title)
1928					}
1929				}
1930			}
1931			// Print the target node
1932			fmt.Fprintf(&sb, "%s [%s] %s\n", target.ID, target.Status, target.Title)
1933			// Print dependents (what depends on this node)
1934			var children []string
1935			for _, other := range sortedKeys(byID) {
1936				if byID[other].HasDep(rootID) {
1937					children = append(children, other)
1938				}
1939			}
1940			for _, child := range children {
1941				s.printTree(&sb, byID, child, "  ", true)
1942			}
1943			return sb.String(), nil
1944		}
1945	
1946		// Find roots (beads that have no dependencies themselves)
1947		var roots []string
1948		for _, b := range beads {
1949			if len(b.Dependencies) == 0 {
1950				roots = append(roots, b.ID)
1951			}
1952		}
1953		sort.Strings(roots)
1954	
1955		var sb strings.Builder
1956		for i, root := range roots {
1957			s.printTree(&sb, byID, root, "", i == len(roots)-1)
1958		}
1959		return sb.String(), nil
1960	}
1961	
1962	func (s *Store) printTree(sb *strings.Builder, byID map[string]*Bead, id, prefix string, last bool) {
1963		b, ok := byID[id]
1964		if !ok {
1965			return
1966		}
1967	
1968		connector := "├── "
1969		if last {
1970			connector = "└── "
1971		}
1972		if prefix == "" {
1973			connector = ""
1974		}
1975	
1976		fmt.Fprintf(sb, "%s%s%s [%s] %s\n", prefix, connector, b.ID, b.Status, b.Title)
1977	
1978		// Find beads that depend on this one (children in the tree)
1979		var children []string
1980		for _, other := range sortedKeys(byID) {
1981			if byID[other].HasDep(id) {
1982				children = append(children, other)
1983			}
1984		}
1985	
1986		childPrefix := prefix
1987		if prefix != "" {
1988			if last {
1989				childPrefix += "    "
1990			} else {
1991				childPrefix += "│   "
1992			}
1993		}
1994	
1995		for i, child := range children {
1996			s.printTree(sb, byID, child, childPrefix, i == len(children)-1)
1997		}
1998	}
1999	
2000	// depChainUp returns the direct dependencies of a bead (upstream IDs).
2001	func (s *Store) depChainUp(byID map[string]*Bead, id string) []string {
2002		b, ok := byID[id]
2003		if !ok {
2004			return nil
2005		}
2006		return b.DepIDs()
2007	}
