89	// writeEventsAttachment writes the given events to the bead's sidecar file
90	// atomically (temp + rename) and creates the parent directory. An empty
91	// slice removes the sidecar.
92	func (s *Store) writeEventsAttachment(beadID string, events []BeadEvent) error {
93		dir := s.attachmentDir(beadID)
94		path := s.eventsAttachmentPath(beadID)
95		if len(events) == 0 {
96			_ = os.Remove(path)
97			return nil
98		}
99		if err := os.MkdirAll(dir, 0o755); err != nil {
100			return fmt.Errorf("bead: mkdir attachments: %w", err)
101		}
102		var buf bytes.Buffer
103		enc := json.NewEncoder(&buf)
104		enc.SetEscapeHTML(false)
105		for _, e := range events {
106			row := map[string]any{
107				"kind":       e.Kind,
108				"summary":    e.Summary,
109				"body":       e.Body,
110				"actor":      e.Actor,
111				"created_at": e.CreatedAt.UTC().Format(time.RFC3339Nano),
112				"source":     e.Source,
113			}
114			if err := enc.Encode(row); err != nil {
115				return fmt.Errorf("bead: encode events attachment: %w", err)
116			}
117		}
118		return writeAtomicFile(path, buf.Bytes())
119	}
