121	// eventsForBead returns the bead's events from whichever physical store
122	// currently holds them: the inline Extra["events"] array, or the externalized
123	// sidecar referenced by Extra[events_attachment]. When both are present the
124	// sidecar wins, matching the externalize-then-clear ordering used by Close.
125	func (s *Store) eventsForBead(b *Bead) ([]BeadEvent, error) {
126		if b == nil {
127			return nil, nil
128		}
129		if hasEventsAttachment(b) {
130			return s.readEventsAttachment(b.ID)
131		}
132		if b.Extra == nil {
133			return nil, nil
134		}
135		if raw, ok := b.Extra["events"]; ok {
136			return decodeBeadEvents(raw), nil
137		}
138		return nil, nil
139	}
