159	// externalizeEventsInPlace moves a bead's inline events to its sidecar. It
160	// mutates b: drops Extra["events"] and sets Extra[events_attachment]. The
161	// sidecar file is written first so a crash leaves the inline copy intact;
162	// after the row is persisted the inline copy is dropped.
163	//
164	// No-op when there are no inline events to move (already externalized, or
165	// never had any). Removes Extra[events_attachment] when the bead has neither
166	// inline nor attached events so the row stays clean.
167	func (s *Store) externalizeEventsInPlace(b *Bead) error {
168		if b == nil {
169			return nil
170		}
171		if s.axonGraphQLActive() {
172			return nil
173		}
174		if b.Extra == nil {
175			b.Extra = make(map[string]any)
176		}
177		var inline []BeadEvent
178		if raw, ok := b.Extra["events"]; ok {
179			inline = decodeBeadEvents(raw)
180		}
181		if len(inline) == 0 {
182			return nil
183		}
184		if err := s.writeEventsAttachment(b.ID, inline); err != nil {
185			return err
186		}
187		delete(b.Extra, "events")
188		b.Extra[EventsAttachmentExtraKey] = eventsAttachmentRelPath(b.ID)
189		return nil
190	}
