191	// DocumentWrite is the resolver for the documentWrite mutation.
192	func (r *mutationResolver) DocumentWrite(ctx context.Context, path string, content string) (*Document, error) {
193		if r.workingDir(ctx) == "" {
194			return nil, fmt.Errorf("working directory not configured")
195		}
196		if path == "" {
197			return nil, fmt.Errorf("path is required")
198		}
199	
200		cleaned := filepath.Clean(path)
201		if strings.Contains(cleaned, "..") {
202			return nil, fmt.Errorf("invalid path: must not contain ..")
203		}
204	
205		libPath, err := r.libraryPath(ctx)
206		if err != nil {
207			return nil, err
208		}
209	
210		fullPath := filepath.Join(libPath, cleaned)
211		if err := os.MkdirAll(filepath.Dir(fullPath), 0o755); err != nil {
212			return nil, fmt.Errorf("creating directory: %w", err)
213		}
214		if err := os.WriteFile(fullPath, []byte(content), 0o644); err != nil {
215			return nil, fmt.Errorf("writing document: %w", err)
216		}
217	
218		// Rebuild graph to pick up the newly written file and return the document.
219		graph, err := docgraph.BuildGraphWithConfig(r.workingDir(ctx))
220		if err != nil {
221			// File was written; return a minimal document rather than failing.
222			return &Document{
223				ID:         cleaned,
224				Path:       cleaned,
225				DependsOn:  []string{},
226				Inputs:     []string{},
227				Dependents: []string{},
228			}, nil
229		}
230	
231		// Look up the document by its cleaned path.
232		if id, ok := graph.PathToID[cleaned]; ok {
233			if doc, ok := graph.Documents[id]; ok {
234				return docToGQL(*doc), nil
235			}
236		}
237	
238		// File written but not yet in graph (e.g., missing DDx frontmatter).
239		return &Document{
240			ID:         cleaned,
241			Path:       cleaned,
242			DependsOn:  []string{},
243			Inputs:     []string{},
244			Dependents: []string{},
245		}, nil
246	}
