267	// StartWorker is the resolver for the startWorker field.
268	//
269	// SD-024 Stage 1: the resolver flows through config.LoadAndResolve so the
270	// project's .ddx/config.yaml drives default harness/profile/effort/label
271	// values when the GraphQL input leaves them unset. Input fields are layered
272	// onto config as CLIOverrides — when present they win over the on-disk
273	// values. The resolved values are forwarded to ActionDispatcher (and ultimately
274	// to runWorker, which re-loads config to drive the loop's durable knobs like
275	// review_max_retries / no_progress_cooldown / heartbeat_interval). This
276	// closes the GraphQL bypass where hardcoded "smart"/"medium" defaults
277	// shadowed the on-disk config.
278	func (r *mutationResolver) StartWorker(ctx context.Context, input StartWorkerInput) (*WorkerDispatchResult, error) {
279		if r.Actions == nil {
280			return nil, fmt.Errorf("execute-loop worker dispatcher is not configured")
281		}
282		projectRoot := r.projectRoot(ctx, input.ProjectID)
283	
284		overrides := config.CLIOverrides{}
285		if input.Harness != nil {
286			overrides.Harness = strings.TrimSpace(*input.Harness)
287		}
288		if input.Profile != nil {
289			overrides.Profile = strings.TrimSpace(*input.Profile)
290		}
291		if input.Effort != nil {
292			overrides.Effort = strings.TrimSpace(*input.Effort)
293		}
294		rcfg, _ := config.LoadAndResolve(projectRoot, overrides)
295	
296		args := map[string]string{}
297		if v := rcfg.Harness(); v != "" {
298			args["harness"] = v
299		}
300		profile := rcfg.Profile()
301		if profile == "" {
302			profile = "smart"
303		}
304		args["profile"] = profile
305		effort := rcfg.Effort()
306		if effort == "" {
307			effort = "medium"
308		}
309		args["effort"] = effort
310		if input.LabelFilter != nil && strings.TrimSpace(*input.LabelFilter) != "" {
311			args["label_filter"] = strings.TrimSpace(*input.LabelFilter)
312		}
313		raw, err := json.Marshal(args)
314		if err != nil {
315			return nil, err
316		}
317		rawArgs := string(raw)
318		return r.Actions.DispatchWorker(ctx, "execute-loop", projectRoot, &rawArgs)
319	}
