489	// ArtifactRegenerate is the resolver for the artifactRegenerate mutation.
490	//
491	// It looks up the artifact by ID and dispatches a server-side regeneration
492	// using the artifact's recorded generator metadata (generatedBy.runId and
493	// promptSummary). When the artifact has no generator metadata it returns a
494	// typed GraphQL error (extension code NO_GENERATOR_METADATA) so the UI can
495	// keep its Regenerate button disabled with an explanatory tooltip.
496	func (r *mutationResolver) ArtifactRegenerate(ctx context.Context, artifactID string) (*ArtifactRegenerateResult, error) {
497		if r.workingDir(ctx) == "" {
498			return nil, &gqlerror.Error{
499				Message:    "working directory not configured",
500				Extensions: map[string]any{"code": "NOT_CONFIGURED"},
501			}
502		}
503	
504		// Resolve the artifact across all known projects so the mutation works
505		// even when the caller passed only the artifact ID. We re-use the same
506		// collection logic used by the Artifact and Artifacts resolvers.
507		artifact, err := findArtifactByID(r.Resolver, artifactID)
508		if err != nil {
509			return nil, err
510		}
511		if artifact == nil {
512			return nil, &gqlerror.Error{
513				Message:    "artifact not found",
514				Extensions: map[string]any{"code": "ARTIFACT_NOT_FOUND"},
515			}
516		}
517		if artifact.GeneratedBy == nil {
518			return nil, &gqlerror.Error{
519				Message: "artifact has no generator metadata; nothing to regenerate",
