321	// gqlPost sends a GraphQL request via HTTP POST and returns the parsed body.
322	// It fails the test immediately on HTTP errors or top-level GraphQL errors.
323	func gqlPost(t *testing.T, h http.Handler, query string) map[string]json.RawMessage {
324		t.Helper()
325		rawBody, _ := json.Marshal(map[string]string{"query": query})
326		req := httptest.NewRequest(http.MethodPost, "/graphql", bytes.NewReader(rawBody))
327		req.Header.Set("Content-Type", "application/json")
328		w := httptest.NewRecorder()
329		h.ServeHTTP(w, req)
330		if w.Code != http.StatusOK {
331			t.Fatalf("expected 200, got %d: %s", w.Code, w.Body.String())
332		}
333		var resp map[string]json.RawMessage
334		if err := json.Unmarshal(w.Body.Bytes(), &resp); err != nil {
335			t.Fatalf("invalid JSON: %v\nbody: %s", err, w.Body.String())
336		}
337		if errs, ok := resp["errors"]; ok {
338			t.Fatalf("GraphQL errors: %s", errs)
339		}
340		return resp
341	}
