775	// arrive in order and that the subscription closes cleanly.
776	func TestIntegration_Subscription_BeadLifecycle(t *testing.T) {
777		workDir, store := setupIntegrationDir(t)
778		state := newTestStateProvider(workDir, store)
779	
780		// Pre-load 2 lifecycle events into a buffered channel.
781		eventCh := make(chan bead.LifecycleEvent, 4)
782		now := time.Now().UTC()
783		events := []bead.LifecycleEvent{
784			{
785				EventID:   "it-aabb-0001",
786				BeadID:    "it-aabb",
